# 컴포넌트 개요: 05 메타데이터 QA 메시지 어댑터
# 역할: 메타데이터 QA 페이로드를 Playground 채팅용 한국어 markdown 메시지로 변환합니다.
# 주요 입력: 페이로드 (payload) · 필수
# 주요 출력: 메시지 (message)
# 처리 흐름: QA 결과를 답변·표·SQL·관련 메타데이터·경고 순서의 Markdown Message 하나로 렌더링합니다.
# 유지보수 포인트: 이 노드만 최종 Chat Output에 연결해 중간 질문이나 JSON이 대화 기록에 중복 출력되지 않게 합니다.
# =============================================================================

from __future__ import annotations

import json
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, Output
from lfx.schema.message import Message

TABLE_LIMIT = 12
CELL_LIMIT = 160


# 주요 함수: 구조화 결과를 사용자가 읽을 수 있는 단일 Markdown Message로 변환합니다.
# Langflow 클래스와 단위 테스트가 같은 업무 규칙을 쓰도록 일반 Python 값 중심으로 처리합니다.
def build_message(payload_value: Any) -> str:
    payload = _payload(payload_value)
    if not payload:
        return ""
    answer_sections = payload.get("answer_sections") if isinstance(payload.get("answer_sections"), dict) else {}
    if answer_sections:
        sections = _message_from_answer_sections(payload, answer_sections)
        if sections:
            return "\n\n".join(sections)

    sections = []
    answer = str(payload.get("answer_message") or payload.get("message") or "").strip()
    if answer:
        sections.append("### 답변\n" + answer)

    sql_section = _sql_section(_dict(payload.get("metadata_qa")).get("sql_blocks"))
    if sql_section:
        sections.append(sql_section)

    table_section = _table_section(_dict(payload.get("data")))
    if table_section:
        sections.append(table_section)

    refs_section = _refs_section(_dict(payload.get("metadata_qa")).get("source_refs"))
    if refs_section:
        sections.append(refs_section)

    warning_section = _warning_section(_dict(payload.get("trace")))
    if warning_section:
        sections.append(warning_section)
    return "\n\n".join(sections) if sections else json.dumps(payload, ensure_ascii=False, default=str)


# 함수 설명: `_message_from_answer_sections()`는 원본·답변·응답 section을 최종 Message에 넣을 독립 Markdown section으로 렌더링합니다.
def _message_from_answer_sections(payload: dict[str, Any], answer_sections: dict[str, Any]) -> list[str]:
    sections: list[str] = []
    summary = _dict(answer_sections.get("summary"))
    answer = str(summary.get("headline") or payload.get("answer_message") or payload.get("message") or "").strip()
    if answer:
        sections.append("### 답변\n" + answer)

    key_points_section = _key_points_section(answer_sections.get("key_points"))
    if key_points_section:
        sections.append(key_points_section)

    detail_section = _detail_table_section(_dict(answer_sections.get("detail_table")), _dict(payload.get("data")))
    if detail_section:
        sections.append(detail_section)

    sql_section = _sql_section(answer_sections.get("sql_blocks"))
    if sql_section:
        sections.append(sql_section)

    examples_section = _usage_examples_section(answer_sections.get("usage_examples"))
    if examples_section:
        sections.append(examples_section)

    route_hint_section = _route_hint_section(_dict(answer_sections.get("route_hint")))
    if route_hint_section:
        sections.append(route_hint_section)

    if bool(answer_sections.get("show_related_items")):
        related_section = _refs_section(answer_sections.get("related_items") or _dict(payload.get("metadata_qa")).get("source_refs"))
        if related_section:
            sections.append(related_section)

    warning_section = _section_warnings(answer_sections.get("warnings")) or _warning_section(_dict(payload.get("trace")))
    if warning_section:
        sections.append(warning_section)
    return sections


# 함수 설명: `_key_points_section()`는 핵심 항목·응답 section을 최종 Message에 넣을 독립 Markdown section으로 렌더링합니다.
def _key_points_section(value: Any) -> str:
    points = [str(item).strip() for item in value if str(item or "").strip()] if isinstance(value, list) else []
    if not points:
        return ""
    lines = ["### 한눈에 보기"]
    lines.extend(f"- {point}" for point in points[:6])
    return "\n".join(lines)


# 함수 설명: `_detail_table_section()`는 표·응답 section을 최종 Message에 넣을 독립 Markdown section으로 렌더링합니다.
def _detail_table_section(detail_table: dict[str, Any], data: dict[str, Any]) -> str:
    rows = _row_list(detail_table.get("rows")) or (_row_list(data.get("rows")) if detail_table.get("row_source") == "data.rows" else [])
    columns = _string_list(detail_table.get("columns")) or _columns_from_rows(rows)
    if not rows:
        return ""
    title = str(detail_table.get("title") or "관련 메타데이터").strip()
    display_limit = _int(detail_table.get("display_limit"), TABLE_LIMIT)
    preview_rows = rows[:display_limit]
    row_count = int(detail_table.get("row_count") or len(rows))
    note = f"\n\n총 {row_count}건 중 {len(preview_rows)}건을 표시했습니다." if row_count > len(preview_rows) else f"\n\n총 {row_count}건입니다."
    return f"### {title}\n" + _markdown_table(preview_rows, columns) + note


# 함수 설명: `_usage_examples_section()`는 examples·응답 section을 최종 Message에 넣을 독립 Markdown section으로 렌더링합니다.
def _usage_examples_section(value: Any) -> str:
    examples = [str(item).strip() for item in value if str(item or "").strip()] if isinstance(value, list) else []
    if not examples:
        return ""
    lines = ["### 다음에 물어볼 수 있는 질문"]
    lines.extend(f"- {example}" for example in examples[:5])
    return "\n".join(lines)


# 함수 설명: `_route_hint_section()`는 힌트·응답 section을 최종 Message에 넣을 독립 Markdown section으로 렌더링합니다.
def _route_hint_section(route_hint: dict[str, Any]) -> str:
    if not route_hint:
        return ""
    message = str(route_hint.get("message") or "").strip()
    target_route = str(route_hint.get("target_route") or "").strip()
    lines = ["### 권장 실행 경로"]
    if target_route:
        lines.append(f"- 대상 route: `{target_route}`")
    if message:
        lines.append(f"- 안내: {message}")
    return "\n".join(lines) if len(lines) > 1 else ""


# 함수 설명: `_section_warnings()`는 경고을 최종 Message에 넣을 독립 Markdown section으로 렌더링합니다.
def _section_warnings(value: Any) -> str:
    warnings = [item for item in value if isinstance(item, dict)] if isinstance(value, list) else []
    if not warnings:
        return ""
    lines = ["### 참고"]
    for item in warnings[:8]:
        message = str(item.get("message") or item.get("type") or "").strip()
        if message:
            lines.append(f"- {message}")
    return "\n".join(lines) if len(lines) > 1 else ""


# 함수 설명: `_sql_section()`는 응답 section을 최종 Message에 넣을 독립 Markdown section으로 렌더링합니다.
def _sql_section(sql_blocks_value: Any) -> str:
    blocks = [block for block in sql_blocks_value if isinstance(block, dict)] if isinstance(sql_blocks_value, list) else []
    if not blocks:
        return ""
    lines = ["### 등록된 Query Template"]
    for block in blocks[:3]:
        label = str(block.get("label") or "query_template").strip()
        sql = str(block.get("sql") or "").strip()
        if not sql:
            continue
        lines.append(f"#### {label}")
        lines.append("```sql\n" + sql + "\n```")
    return "\n".join(lines)


# 함수 설명: `_table_section()`는 구조화 rows/columns를 최종 답변의 표 section 계약으로 변환합니다.
def _table_section(data: dict[str, Any]) -> str:
    rows = _row_list(data.get("rows"))
    columns = _string_list(data.get("columns")) or _columns_from_rows(rows)
    if not rows:
        return ""
    preview_rows = rows[:TABLE_LIMIT]
    note = f"\n\n총 {len(rows)}건 중 {len(preview_rows)}건을 표시했습니다." if len(rows) > len(preview_rows) else f"\n\n총 {len(rows)}건입니다."
    return "### 관련 메타데이터\n" + _markdown_table(preview_rows, columns) + note


# 함수 설명: `_refs_section()`는 응답 section을 최종 Message에 넣을 독립 Markdown section으로 렌더링합니다.
def _refs_section(value: Any) -> str:
    refs = [ref for ref in value if isinstance(ref, dict)] if isinstance(value, list) else []
    if not refs:
        return ""
    labels = []
    for ref in refs[:10]:
        metadata_type = str(ref.get("metadata_type") or "").strip()
        section = str(ref.get("section") or "").strip()
        key = str(ref.get("key") or "").strip()
        labels.append(":".join(part for part in (metadata_type, section, key) if part))
    return "### 사용한 메타데이터\n" + "\n".join(f"- `{label}`" for label in labels if label)


# 함수 설명: `_warning_section()`는 응답 section을 최종 Message에 넣을 독립 Markdown section으로 렌더링합니다.
def _warning_section(trace: dict[str, Any]) -> str:
    warnings = _list(trace.get("warnings"))
    errors = _list(trace.get("errors"))
    if not warnings and not errors:
        return ""
    lines = ["### 경고/오류"]
    for item in warnings[:8]:
        lines.append(f"- 경고: `{_display(item)}`")
    for item in errors[:8]:
        lines.append(f"- 오류: `{_display(item)}`")
    return "\n".join(lines)


# 함수 설명: `_markdown_table()`는 컬럼과 행을 길이 제한·escape 규칙이 적용된 Markdown 표로 렌더링합니다.
def _markdown_table(rows: list[dict[str, Any]], columns: list[str]) -> str:
    header = "| " + " | ".join(_escape(column) for column in columns) + " |"
    divider = "| " + " | ".join("---" for _ in columns) + " |"
    body = []
    for row in rows:
        body.append("| " + " | ".join(_escape(row.get(column, "")) for column in columns) + " |")
    return "\n".join([header, divider] + body)


# 함수 설명: `_payload()`는 Langflow Data/Message 또는 일반 dict 입력에서 안전한 dict 페이로드 복사본을 꺼냅니다.
def _payload(value: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    return deepcopy(data) if isinstance(data, dict) else {}


# 함수 설명: `_dict()`는 입력값이 dict인지 확인하고 아니면 빈 dict를 반환해 후속 key 접근 오류를 막습니다.
def _dict(value: Any) -> dict[str, Any]:
    return value if isinstance(value, dict) else {}


# 함수 설명: `_list()`는 입력값을 list로 정규화하고 목록이 아닌 값은 안전한 기본 목록으로 바꿉니다.
def _list(value: Any) -> list[Any]:
    return value if isinstance(value, list) else []


# 함수 설명: `_row_list()`는 여러 입력 형태에서 dict인 행만 골라 표준 행 목록으로 반환합니다.
def _row_list(value: Any) -> list[dict[str, Any]]:
    return [dict(row) for row in value if isinstance(row, dict)] if isinstance(value, list) else []


# 함수 설명: `_string_list()`는 여러 형태의 입력에서 비어 있지 않은 문자열만 뽑아 중복 없는 목록으로 정리합니다.
def _string_list(value: Any) -> list[str]:
    return [str(item) for item in value if str(item or "").strip()] if isinstance(value, list) else []


# 함수 설명: `_columns_from_rows()`는 행 목록의 key 등장 순서를 유지하면서 결과 테이블의 컬럼 목록을 계산합니다.
def _columns_from_rows(rows: list[dict[str, Any]]) -> list[str]:
    columns = []
    for row in rows:
        for key in row:
            if key not in columns:
                columns.append(str(key))
    return columns


# 함수 설명: `_escape()`는 Markdown 표 셀을 깨뜨리는 구분자와 줄바꿈 문자를 안전하게 escape합니다.
def _escape(value: Any) -> str:
    text = _display(value).replace("\n", "<br>").replace("|", "\\|")
    return text[: CELL_LIMIT - 3] + "..." if len(text) > CELL_LIMIT else text


# 함수 설명: `_display()`는 표시값을 Markdown 또는 사용자 화면에서 안전하게 읽을 수 있는 표현으로 변환합니다.
def _display(value: Any) -> str:
    if isinstance(value, (dict, list)):
        return json.dumps(value, ensure_ascii=False, default=str)
    return "" if value is None else str(value)


# 함수 설명: `_int()`는 문자열이나 숫자 입력을 정수로 변환하고 실패하면 안전한 기본값을 사용합니다.
def _int(value: Any, default: int) -> int:
    try:
        return max(1, int(value))
    except Exception:
        return default


# Langflow 컴포넌트 클래스: inputs/outputs가 캔버스 포트와 JSON edge 계약을 정의합니다.
# 실제 업무 규칙은 위의 주요 함수에 두어 UI 실행과 단위 테스트가 같은 로직을 사용합니다.
class MetadataQaMessageAdapter(Component):
    display_name = "05 메타데이터 QA 메시지 어댑터"
    description = "메타데이터 QA 페이로드를 Playground 채팅용 한국어 markdown 메시지로 변환합니다."
    inputs = [DataInput(name="payload", display_name="페이로드", required=True)]
    outputs = [Output(name="message", display_name="메시지", method="build_output_message", types=["Message"])]

    # Langflow 출력 함수: '메시지 (message)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_output_message(self) -> Message:
        return Message(text=build_message(getattr(self, "payload", None)))

# -*- coding: utf-8 -*-
# =============================================================================
# 컴포넌트 개요: 01 선택 Flow API 메시지 호출기
# 역할: Smart Router가 선택한 branch의 원문 메시지를 하위 Langflow Run API로 전달하고, 하위 flow의 표시 메시지만 반환합니다.
# 주요 입력: Flow 입력 (flow_input) · 필수, 하위 Flow endpoint/URL (api_url) · 필수, Langflow API 키 (api_key), 세션 ID
#        (session_id), Route 이름 (route_name), 연결 제한 시간(초) (connect_timeout_seconds), 응답 제한 시간(초)
#        (read_timeout_seconds)
# 주요 출력: 메시지 (message), 호출 상태 (status_data)
# 처리 흐름: Smart Router가 선택한 하위 Flow Run API에 원문 질문과 부모 세션을 한 번만 전달하고 최종 Message를 추출합니다.
# 유지보수 포인트: nested child의 Chat 저장만 request tweak로 끄고 부모 Router가 세션 메시지를 한 번만 소유합니다.
# =============================================================================

from __future__ import annotations

import json
import os
import time
import uuid
from copy import deepcopy
from typing import Any

import requests
from lfx.custom.custom_component.component import Component
from lfx.io import MessageTextInput, Output, SecretStrInput
from lfx.schema.data import Data
from lfx.schema.message import Message

_HTTP_SESSION = requests.Session()
DEFAULT_LANGFLOW_BASE_URL = "http://127.0.0.1:7860"
DEFAULT_CONNECT_TIMEOUT_SECONDS = 5
DEFAULT_READ_TIMEOUT_SECONDS = 240
NESTED_CHAT_STORAGE_TWEAKS = {
    "Chat Input": {"should_store_message": False},
    "Chat Output": {"should_store_message": False},
}


# 주요 함수: 선택된 하위 Flow API를 호출하고 중간 출력이 아닌 최종 Message만 반환합니다.
# Langflow 클래스와 단위 테스트가 같은 업무 규칙을 쓰도록 일반 Python 값 중심으로 처리합니다.
def run_flow_api_message(
    flow_input_value: Any,
    *,
    api_url: str = "",
    api_key: str = "",
    session_id: str = "",
    session_source_value: Any = None,
    timeout_seconds: Any = None,
    connect_timeout_seconds: Any = DEFAULT_CONNECT_TIMEOUT_SECONDS,
    read_timeout_seconds: Any = DEFAULT_READ_TIMEOUT_SECONDS,
    route_name: str = "",
    post_func: Any = None,
) -> dict[str, Any]:
    flow_input = _input_text(flow_input_value, preserve=True)
    session_source = session_source_value if session_source_value is not None else flow_input_value
    session_id_value = _session_id(session_source, session_id)
    api_url_value = _resolve_api_url(api_url)
    warnings: list[dict[str, Any]] = []
    errors: list[dict[str, Any]] = []

    if not flow_input.strip():
        errors.append({"type": "empty_input", "message": "하위 flow로 전달할 입력이 비어 있습니다."})
    if _looks_like_route_message(flow_input):
        errors.append(
            {
                "type": "route_message_used_as_input",
                "message": (
                    "Smart Router Route Message가 사용자 질문 대신 전달되었습니다. "
                    "API 호출 route의 Route Message를 비우고 Smart Router route output이 원문을 그대로 보내도록 설정하세요."
                ),
            }
        )
    if not _clean(api_url):
        errors.append({"type": "missing_api_url", "message": "하위 flow의 Langflow Run API URL이 비어 있습니다."})

    if errors:
        return _message_result(
            status="error",
            message=_format_errors(errors),
            flow_input=flow_input,
            api_url=api_url_value,
            session_id=session_id_value,
            warnings=warnings,
            errors=errors,
            raw_response={},
            duration_ms=0,
            route_name=_clean(route_name),
        )

    request_body = {
        "input_value": flow_input,
        "input_type": "chat",
        "output_type": "chat",
        # Child Flow는 direct Playground 표시를 위해 저장을 기본 활성화합니다.
        # Router nested 호출에서만 display_name 기반 tweak로 child 질문/답변 저장을 끕니다.
        "tweaks": deepcopy(NESTED_CHAT_STORAGE_TWEAKS),
    }
    if session_id_value:
        request_body["session_id"] = session_id_value
    headers = {"Content-Type": "application/json"}
    api_key_value = _secret_text(api_key) or _clean(os.getenv("LANGFLOW_API_KEY", ""))
    if api_key_value:
        headers["x-api-key"] = api_key_value

    started = time.monotonic()
    post = post_func or _HTTP_SESSION.post
    timeout = _timeout_value(timeout_seconds, connect_timeout_seconds, read_timeout_seconds)
    try:
        response = post(api_url_value, json=request_body, headers=headers, timeout=timeout)
        http_status = int(getattr(response, "status_code", 200) or 200)
        raise_for_status = getattr(response, "raise_for_status", None)
        if callable(raise_for_status):
            raise_for_status()
        parsed = response.json() if callable(getattr(response, "json", None)) else response
    except Exception as exc:
        return _message_result(
            status="error",
            message=f"하위 flow API 호출에 실패했습니다: {exc}",
            flow_input=flow_input,
            api_url=api_url_value,
            session_id=session_id_value,
            warnings=warnings,
            errors=[{"type": "api_call_failed", "message": str(exc)}],
            raw_response={},
            duration_ms=_duration_ms(started),
            route_name=_clean(route_name),
        )

    raw_response = parsed if isinstance(parsed, dict) else {"response": parsed}
    message = _extract_message_text(raw_response)
    child_status = _extract_child_status(raw_response)
    child_failed = child_status in {"error", "failed", "failure"}
    if not message:
        message = "하위 flow가 표시 메시지를 반환하지 않았습니다."
        errors.append({"type": "missing_downstream_message", "message": message})
    result = _message_result(
        status="error" if child_failed or errors else "ok",
        message=message,
        flow_input=flow_input,
        api_url=api_url_value,
        session_id=session_id_value,
        warnings=warnings,
        errors=errors,
        raw_response=raw_response,
        duration_ms=_duration_ms(started),
        route_name=_clean(route_name),
    )
    result["request_body"] = request_body
    result["http_status"] = http_status
    result["downstream_status"] = child_status or "unknown"
    return result


# 함수 설명: `_message_result()`는 하위 Flow 호출 상태와 최종 Message를 Router 공통 결과 구조로 묶습니다.
def _message_result(
    *,
    status: str,
    message: str,
    flow_input: str,
    api_url: str,
    session_id: str,
    warnings: list[dict[str, Any]],
    errors: list[dict[str, Any]],
    raw_response: dict[str, Any],
    duration_ms: int,
    route_name: str,
) -> dict[str, Any]:
    return {
        "status": status,
        "message": message,
        "flow_input": flow_input,
        "api_url": api_url,
        "session_id": session_id,
        "warnings": warnings,
        "errors": errors,
        "raw_response": raw_response,
        "duration_ms": duration_ms,
        "route_name": route_name,
    }


# 함수 설명: `_looks_like_route_message()`는 입력값이 LIKE·라우팅·Message 조건에 해당하는지 부작용 없이 bool로 판정합니다.
def _looks_like_route_message(value: Any) -> bool:
    parsed = _parse_json_dict(str(value or ""))
    if not parsed:
        return False
    keys = {str(key) for key in parsed}
    return bool(keys & {"route", "selected_route", "route_name"}) and len(keys) <= 3


# 함수 설명: `_format_errors()`는 오류을 Markdown 또는 사용자 화면에서 안전하게 읽을 수 있는 표현으로 변환합니다.
def _format_errors(errors: list[dict[str, Any]]) -> str:
    return "\n".join(f"- {error.get('message', '')}" for error in errors if error.get("message"))


# 함수 설명: `_extract_message_text()`는 Langflow Run API의 중첩 응답에서 최종 사용자 Message 텍스트를 우선순위대로 찾습니다.
def _extract_message_text(value: Any) -> str:
    return _extract_message_text_inner(value, set())


# 함수 설명: `_extract_child_status()`는 하위 Flow 응답의 status를 여러 envelope 형식에서 우선순위대로 추출합니다.
def _extract_child_status(value: Any) -> str:
    if not isinstance(value, dict):
        return ""
    api_response = value.get("api_response")
    if isinstance(api_response, dict) and str(api_response.get("status") or "").strip():
        return str(api_response.get("status")).strip().lower()
    if str(value.get("status") or "").strip():
        return str(value.get("status")).strip().lower()
    for key in ("outputs", "results", "data", "artifacts"):
        nested = value.get(key)
        values = nested if isinstance(nested, list) else [nested]
        for item in values:
            status = _extract_child_status(item)
            if status:
                return status
    return ""


# 함수 설명: `_extract_message_text_inner()`는 복합 입력이나 응답에서 Message·문자열·inner을 찾아 검증 가능한 기본 Python 값으로 변환합니다.
def _extract_message_text_inner(value: Any, seen: set[int]) -> str:
    if value is None:
        return ""
    value_id = id(value)
    if value_id in seen:
        return ""
    seen.add(value_id)
    for attr in ("text", "content", "message"):
        text = getattr(value, attr, None)
        if isinstance(text, str) and text.strip():
            return text.strip()
    if isinstance(value, str):
        parsed = _parse_json_dict(value)
        if parsed:
            return _extract_message_text_inner(parsed, seen)
        return value.strip()
    if isinstance(value, dict):
        for key in ("api_response", "display_message", "answer_message", "answer", "text", "content", "output", "response", "message"):
            text = _extract_message_text_inner(value.get(key), seen)
            if text:
                return text
        for key in ("results", "artifacts", "outputs", "data", "messages"):
            text = _extract_message_text_inner(value.get(key), seen)
            if text:
                return text
    if isinstance(value, list):
        for item in value:
            text = _extract_message_text_inner(item, seen)
            if text:
                return text
    return ""


# 함수 설명: `_parse_json_dict()`는 복합 입력이나 응답에서 JSON·DICT을 찾아 검증 가능한 기본 Python 값으로 변환합니다.
def _parse_json_dict(value: str) -> dict[str, Any]:
    text = _clean(value)
    if not text:
        return {}
    if text.startswith("```"):
        text = text.strip("`").strip()
        if text.lower().startswith("json"):
            text = text[4:].strip()
    try:
        parsed = json.loads(text)
    except Exception:
        return {}
    return deepcopy(parsed) if isinstance(parsed, dict) else {}


# 함수 설명: `_input_text()`는 Message/Data/JSON 입력에서 하위 Flow에 그대로 전달할 원문 질문을 추출합니다.
def _input_text(value: Any, *, preserve: bool = False) -> str:
    if value is None:
        return ""
    for attr in ("text", "content", "message"):
        text = getattr(value, attr, None)
        if isinstance(text, str):
            return text if preserve else text.strip()
    if isinstance(value, str):
        return value if preserve else value.strip()
    data = getattr(value, "data", value)
    if isinstance(data, dict):
        for key in ("input_value", "question", "raw_text", "message", "text"):
            text = data.get(key)
            if isinstance(text, str):
                return text if preserve else text.strip()
    return ""


# 함수 설명: `_session_id()`는 명시 입력과 부모 Message의 session 정보를 우선순위대로 해석합니다.
def _session_id(source_value: Any, explicit_session_id: Any) -> str:
    explicit = _clean(explicit_session_id)
    if explicit:
        return explicit
    for attr in ("session_id", "sessionId"):
        candidate = getattr(source_value, attr, None)
        if _clean(candidate):
            return _clean(candidate)
    data = getattr(source_value, "data", source_value)
    if isinstance(data, dict):
        for key in ("session_id", "sessionId"):
            candidate = data.get(key)
            if _clean(candidate):
                return _clean(candidate)
        request = data.get("request")
        if isinstance(request, dict):
            candidate = request.get("session_id") or request.get("sessionId")
            if _clean(candidate):
                return _clean(candidate)
    if _input_text(source_value, preserve=False):
        return f"route_flow_{uuid.uuid4().hex}"
    return ""


# 함수 설명: `_clean()`는 선택 입력을 안전한 문자열로 바꾸고 불필요한 앞뒤 공백을 제거합니다.
def _clean(value: Any) -> str:
    if value is None:
        return ""
    return str(value).strip()


# 함수 설명: `_resolve_api_url()`는 여러 API·URL 후보와 우선순위를 검토해 실제 사용할 값을 확정합니다.
def _resolve_api_url(value: Any) -> str:
    configured = _clean(value)
    if not configured:
        return ""
    if configured.lower().startswith(("http://", "https://")):
        return configured
    base_url = (
        _clean(os.getenv("LANGFLOW_BASE_URL", ""))
        or _clean(os.getenv("LANGFLOW_API_BASE_URL", ""))
        or DEFAULT_LANGFLOW_BASE_URL
    ).rstrip("/")
    if configured.startswith("/"):
        return f"{base_url}{configured}"
    if configured.startswith("api/"):
        return f"{base_url}/{configured}"
    return f"{base_url}/api/v1/run/{configured}"


# 함수 설명: `_secret_text()`는 SecretStr 또는 일반 입력에서 노출 없이 실제 credential 문자열만 꺼냅니다.
def _secret_text(value: Any) -> str:
    getter = getattr(value, "get_secret_value", None)
    if callable(getter):
        return _clean(getter())
    return _clean(value)


# 함수 설명: `_safe_int()`는 예외를 발생시키지 않고 값을 정수로 바꾸며 허용되지 않는 값은 기본값으로 처리합니다.
def _safe_int(value: Any, default: int) -> int:
    try:
        return max(1, int(str(value or "").strip()))
    except Exception:
        return default


# 함수 설명: `_timeout_value()`는 호환 timeout 입력과 connect/read timeout을 requests가 요구하는 값으로 정규화합니다.
def _timeout_value(timeout_seconds: Any, connect_timeout_seconds: Any, read_timeout_seconds: Any) -> Any:
    if timeout_seconds not in (None, ""):
        return _safe_int(timeout_seconds, default=DEFAULT_READ_TIMEOUT_SECONDS)
    return (
        _safe_int(connect_timeout_seconds, default=DEFAULT_CONNECT_TIMEOUT_SECONDS),
        _safe_int(read_timeout_seconds, default=DEFAULT_READ_TIMEOUT_SECONDS),
    )


# 함수 설명: `_duration_ms()`는 시작 시각부터 현재까지의 API 호출 시간을 밀리초 정수로 계산합니다.
def _duration_ms(started: float) -> int:
    return max(0, int((time.monotonic() - started) * 1000))


# Langflow 컴포넌트 클래스: inputs/outputs가 캔버스 포트와 JSON edge 계약을 정의합니다.
# 실제 업무 규칙은 위의 주요 함수에 두어 UI 실행과 단위 테스트가 같은 로직을 사용합니다.
class FlowApiMessageCaller(Component):
    display_name = "01 선택 Flow API 메시지 호출기"
    description = "Smart Router가 선택한 branch의 원문 메시지를 하위 Langflow Run API로 전달하고, 하위 flow의 표시 메시지만 반환합니다."
    inputs = [
        MessageTextInput(name="flow_input", display_name="Flow 입력", required=True),
        MessageTextInput(
            name="api_url",
            display_name="하위 Flow endpoint/URL",
            value="",
            required=True,
            info="endpoint_name, /api/v1/run/... 경로 또는 전체 URL을 입력합니다. 상대값은 LANGFLOW_BASE_URL 기준으로 해석합니다.",
        ),
        SecretStrInput(name="api_key", display_name="Langflow API 키", value="", required=False, advanced=True),
        MessageTextInput(name="session_id", display_name="세션 ID", value="", required=False, advanced=True),
        MessageTextInput(name="route_name", display_name="Route 이름", value="", required=False, advanced=True),
        MessageTextInput(
            name="connect_timeout_seconds",
            display_name="연결 제한 시간(초)",
            value=str(DEFAULT_CONNECT_TIMEOUT_SECONDS),
            required=False,
            advanced=True,
        ),
        MessageTextInput(
            name="read_timeout_seconds",
            display_name="응답 제한 시간(초)",
            value=str(DEFAULT_READ_TIMEOUT_SECONDS),
            required=False,
            advanced=True,
        ),
    ]
    outputs = [
        Output(name="message", display_name="메시지", method="build_message", types=["Message"], group_outputs=True),
        Output(name="status_data", display_name="호출 상태", method="build_status", types=["Data"], group_outputs=True),
    ]

    # 함수 설명: `_run_once()`는 같은 Langflow 노드 실행에서 하위 Flow API가 중복 호출되지 않도록 결과를 한 번만 계산해 재사용합니다.
    def _run_once(self) -> dict[str, Any]:
        if not hasattr(self, "_cached_result"):
            session_id = getattr(self, "session_id", "")
            if not _clean(session_id):
                session_id = getattr(getattr(self, "graph", None), "session_id", "") or ""
            self._cached_result = run_flow_api_message(
                getattr(self, "flow_input", ""),
                api_url=getattr(self, "api_url", ""),
                api_key=getattr(self, "api_key", ""),
                session_id=session_id,
                connect_timeout_seconds=getattr(
                    self, "connect_timeout_seconds", str(DEFAULT_CONNECT_TIMEOUT_SECONDS)
                ),
                read_timeout_seconds=getattr(self, "read_timeout_seconds", str(DEFAULT_READ_TIMEOUT_SECONDS)),
                route_name=getattr(self, "route_name", ""),
            )
        return self._cached_result

    # Langflow 출력 함수: '메시지 (message)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_message(self) -> Message:
        result = self._run_once()
        return Message(text=_clean(result.get("message")))

    # Langflow 출력 함수: '호출 상태 (status_data)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_status(self) -> Data:
        result = self._run_once()
        return Data(
            data={
                "status": result.get("status"),
                "route_name": result.get("route_name"),
                "http_status": result.get("http_status"),
                "downstream_status": result.get("downstream_status"),
                "duration_ms": result.get("duration_ms"),
                "session_id": result.get("session_id"),
                "errors": result.get("errors", []),
                "warnings": result.get("warnings", []),
            }
        )

# -*- coding: utf-8 -*-
# =============================================================================
# 컴포넌트 개요: 01 선택 Flow API 메시지 호출기
# 역할: Smart Router가 선택한 branch의 원문 메시지를 하위 Langflow Run API로 전달하고, 하위 flow의 표시 메시지만 반환합니다.
# 주요 입력: Flow 입력 (flow_input) · 필수, 하위 Flow endpoint/URL (api_url) · 필수, Langflow API 키 (api_key), 세션 ID
#        (session_id), Route 이름 (route_name), 연결 제한 시간(초) (connect_timeout_seconds), 응답 제한 시간(초)
#        (read_timeout_seconds)
# 주요 출력: 메시지 (message), 호출 상태 (status_data)
# 처리 흐름: Smart Router가 선택한 하위 Flow Run API에 원문 질문과 부모 세션을 한 번만 전달하고 최종 Message를 추출합니다.
# 유지보수 포인트: nested child의 Chat 저장만 request tweak로 끄고 부모 Router가 세션 메시지를 한 번만 소유합니다.
# =============================================================================

from __future__ import annotations

import json
import os
import time
import uuid
from copy import deepcopy
from typing import Any

import requests
from lfx.custom.custom_component.component import Component
from lfx.io import MessageTextInput, Output, SecretStrInput
from lfx.schema.data import Data
from lfx.schema.message import Message

_HTTP_SESSION = requests.Session()
DEFAULT_LANGFLOW_BASE_URL = "http://127.0.0.1:7860"
DEFAULT_CONNECT_TIMEOUT_SECONDS = 5
DEFAULT_READ_TIMEOUT_SECONDS = 240
NESTED_CHAT_STORAGE_TWEAKS = {
    "Chat Input": {"should_store_message": False},
    "Chat Output": {"should_store_message": False},
}


# 주요 함수: 선택된 하위 Flow API를 호출하고 중간 출력이 아닌 최종 Message만 반환합니다.
# Langflow 클래스와 단위 테스트가 같은 업무 규칙을 쓰도록 일반 Python 값 중심으로 처리합니다.
def run_flow_api_message(
    flow_input_value: Any,
    *,
    api_url: str = "",
    api_key: str = "",
    session_id: str = "",
    session_source_value: Any = None,
    timeout_seconds: Any = None,
    connect_timeout_seconds: Any = DEFAULT_CONNECT_TIMEOUT_SECONDS,
    read_timeout_seconds: Any = DEFAULT_READ_TIMEOUT_SECONDS,
    route_name: str = "",
    post_func: Any = None,
) -> dict[str, Any]:
    flow_input = _input_text(flow_input_value, preserve=True)
    session_source = session_source_value if session_source_value is not None else flow_input_value
    session_id_value = _session_id(session_source, session_id)
    api_url_value = _resolve_api_url(api_url)
    warnings: list[dict[str, Any]] = []
    errors: list[dict[str, Any]] = []

    if not flow_input.strip():
        errors.append({"type": "empty_input", "message": "하위 flow로 전달할 입력이 비어 있습니다."})
    if _looks_like_route_message(flow_input):
        errors.append(
            {
                "type": "route_message_used_as_input",
                "message": (
                    "Smart Router Route Message가 사용자 질문 대신 전달되었습니다. "
                    "API 호출 route의 Route Message를 비우고 Smart Router route output이 원문을 그대로 보내도록 설정하세요."
                ),
            }
        )
    if not _clean(api_url):
        errors.append({"type": "missing_api_url", "message": "하위 flow의 Langflow Run API URL이 비어 있습니다."})

    if errors:
        return _message_result(
            status="error",
            message=_format_errors(errors),
            flow_input=flow_input,
            api_url=api_url_value,
            session_id=session_id_value,
            warnings=warnings,
            errors=errors,
            raw_response={},
            duration_ms=0,
            route_name=_clean(route_name),
        )

    request_body = {
        "input_value": flow_input,
        "input_type": "chat",
        "output_type": "chat",
        # Child Flow는 direct Playground 표시를 위해 저장을 기본 활성화합니다.
        # Router nested 호출에서만 display_name 기반 tweak로 child 질문/답변 저장을 끕니다.
        "tweaks": deepcopy(NESTED_CHAT_STORAGE_TWEAKS),
    }
    if session_id_value:
        request_body["session_id"] = session_id_value
    headers = {"Content-Type": "application/json"}
    api_key_value = _secret_text(api_key) or _clean(os.getenv("LANGFLOW_API_KEY", ""))
    if api_key_value:
        headers["x-api-key"] = api_key_value

    started = time.monotonic()
    post = post_func or _HTTP_SESSION.post
    timeout = _timeout_value(timeout_seconds, connect_timeout_seconds, read_timeout_seconds)
    try:
        response = post(api_url_value, json=request_body, headers=headers, timeout=timeout)
        http_status = int(getattr(response, "status_code", 200) or 200)
        raise_for_status = getattr(response, "raise_for_status", None)
        if callable(raise_for_status):
            raise_for_status()
        parsed = response.json() if callable(getattr(response, "json", None)) else response
    except Exception as exc:
        return _message_result(
            status="error",
            message=f"하위 flow API 호출에 실패했습니다: {exc}",
            flow_input=flow_input,
            api_url=api_url_value,
            session_id=session_id_value,
            warnings=warnings,
            errors=[{"type": "api_call_failed", "message": str(exc)}],
            raw_response={},
            duration_ms=_duration_ms(started),
            route_name=_clean(route_name),
        )

    raw_response = parsed if isinstance(parsed, dict) else {"response": parsed}
    message = _extract_message_text(raw_response)
    child_status = _extract_child_status(raw_response)
    child_failed = child_status in {"error", "failed", "failure"}
    if not message:
        message = "하위 flow가 표시 메시지를 반환하지 않았습니다."
        errors.append({"type": "missing_downstream_message", "message": message})
    result = _message_result(
        status="error" if child_failed or errors else "ok",
        message=message,
        flow_input=flow_input,
        api_url=api_url_value,
        session_id=session_id_value,
        warnings=warnings,
        errors=errors,
        raw_response=raw_response,
        duration_ms=_duration_ms(started),
        route_name=_clean(route_name),
    )
    result["request_body"] = request_body
    result["http_status"] = http_status
    result["downstream_status"] = child_status or "unknown"
    return result


# 함수 설명: `_message_result()`는 하위 Flow 호출 상태와 최종 Message를 Router 공통 결과 구조로 묶습니다.
def _message_result(
    *,
    status: str,
    message: str,
    flow_input: str,
    api_url: str,
    session_id: str,
    warnings: list[dict[str, Any]],
    errors: list[dict[str, Any]],
    raw_response: dict[str, Any],
    duration_ms: int,
    route_name: str,
) -> dict[str, Any]:
    return {
        "status": status,
        "message": message,
        "flow_input": flow_input,
        "api_url": api_url,
        "session_id": session_id,
        "warnings": warnings,
        "errors": errors,
        "raw_response": raw_response,
        "duration_ms": duration_ms,
        "route_name": route_name,
    }


# 함수 설명: `_looks_like_route_message()`는 입력값이 LIKE·라우팅·Message 조건에 해당하는지 부작용 없이 bool로 판정합니다.
def _looks_like_route_message(value: Any) -> bool:
    parsed = _parse_json_dict(str(value or ""))
    if not parsed:
        return False
    keys = {str(key) for key in parsed}
    return bool(keys & {"route", "selected_route", "route_name"}) and len(keys) <= 3


# 함수 설명: `_format_errors()`는 오류을 Markdown 또는 사용자 화면에서 안전하게 읽을 수 있는 표현으로 변환합니다.
def _format_errors(errors: list[dict[str, Any]]) -> str:
    return "\n".join(f"- {error.get('message', '')}" for error in errors if error.get("message"))


# 함수 설명: `_extract_message_text()`는 Langflow Run API의 중첩 응답에서 최종 사용자 Message 텍스트를 우선순위대로 찾습니다.
def _extract_message_text(value: Any) -> str:
    return _extract_message_text_inner(value, set())


# 함수 설명: `_extract_child_status()`는 하위 Flow 응답의 status를 여러 envelope 형식에서 우선순위대로 추출합니다.
def _extract_child_status(value: Any) -> str:
    if not isinstance(value, dict):
        return ""
    api_response = value.get("api_response")
    if isinstance(api_response, dict) and str(api_response.get("status") or "").strip():
        return str(api_response.get("status")).strip().lower()
    if str(value.get("status") or "").strip():
        return str(value.get("status")).strip().lower()
    for key in ("outputs", "results", "data", "artifacts"):
        nested = value.get(key)
        values = nested if isinstance(nested, list) else [nested]
        for item in values:
            status = _extract_child_status(item)
            if status:
                return status
    return ""


# 함수 설명: `_extract_message_text_inner()`는 복합 입력이나 응답에서 Message·문자열·inner을 찾아 검증 가능한 기본 Python 값으로 변환합니다.
def _extract_message_text_inner(value: Any, seen: set[int]) -> str:
    if value is None:
        return ""
    value_id = id(value)
    if value_id in seen:
        return ""
    seen.add(value_id)
    for attr in ("text", "content", "message"):
        text = getattr(value, attr, None)
        if isinstance(text, str) and text.strip():
            return text.strip()
    if isinstance(value, str):
        parsed = _parse_json_dict(value)
        if parsed:
            return _extract_message_text_inner(parsed, seen)
        return value.strip()
    if isinstance(value, dict):
        for key in ("api_response", "display_message", "answer_message", "answer", "text", "content", "output", "response", "message"):
            text = _extract_message_text_inner(value.get(key), seen)
            if text:
                return text
        for key in ("results", "artifacts", "outputs", "data", "messages"):
            text = _extract_message_text_inner(value.get(key), seen)
            if text:
                return text
    if isinstance(value, list):
        for item in value:
            text = _extract_message_text_inner(item, seen)
            if text:
                return text
    return ""


# 함수 설명: `_parse_json_dict()`는 복합 입력이나 응답에서 JSON·DICT을 찾아 검증 가능한 기본 Python 값으로 변환합니다.
def _parse_json_dict(value: str) -> dict[str, Any]:
    text = _clean(value)
    if not text:
        return {}
    if text.startswith("```"):
        text = text.strip("`").strip()
        if text.lower().startswith("json"):
            text = text[4:].strip()
    try:
        parsed = json.loads(text)
    except Exception:
        return {}
    return deepcopy(parsed) if isinstance(parsed, dict) else {}


# 함수 설명: `_input_text()`는 Message/Data/JSON 입력에서 하위 Flow에 그대로 전달할 원문 질문을 추출합니다.
def _input_text(value: Any, *, preserve: bool = False) -> str:
    if value is None:
        return ""
    for attr in ("text", "content", "message"):
        text = getattr(value, attr, None)
        if isinstance(text, str):
            return text if preserve else text.strip()
    if isinstance(value, str):
        return value if preserve else value.strip()
    data = getattr(value, "data", value)
    if isinstance(data, dict):
        for key in ("input_value", "question", "raw_text", "message", "text"):
            text = data.get(key)
            if isinstance(text, str):
                return text if preserve else text.strip()
    return ""


# 함수 설명: `_session_id()`는 명시 입력과 부모 Message의 session 정보를 우선순위대로 해석합니다.
def _session_id(source_value: Any, explicit_session_id: Any) -> str:
    explicit = _clean(explicit_session_id)
    if explicit:
        return explicit
    for attr in ("session_id", "sessionId"):
        candidate = getattr(source_value, attr, None)
        if _clean(candidate):
            return _clean(candidate)
    data = getattr(source_value, "data", source_value)
    if isinstance(data, dict):
        for key in ("session_id", "sessionId"):
            candidate = data.get(key)
            if _clean(candidate):
                return _clean(candidate)
        request = data.get("request")
        if isinstance(request, dict):
            candidate = request.get("session_id") or request.get("sessionId")
            if _clean(candidate):
                return _clean(candidate)
    if _input_text(source_value, preserve=False):
        return f"route_flow_{uuid.uuid4().hex}"
    return ""


# 함수 설명: `_clean()`는 선택 입력을 안전한 문자열로 바꾸고 불필요한 앞뒤 공백을 제거합니다.
def _clean(value: Any) -> str:
    if value is None:
        return ""
    return str(value).strip()


# 함수 설명: `_resolve_api_url()`는 여러 API·URL 후보와 우선순위를 검토해 실제 사용할 값을 확정합니다.
def _resolve_api_url(value: Any) -> str:
    configured = _clean(value)
    if not configured:
        return ""
    if configured.lower().startswith(("http://", "https://")):
        return configured
    base_url = (
        _clean(os.getenv("LANGFLOW_BASE_URL", ""))
        or _clean(os.getenv("LANGFLOW_API_BASE_URL", ""))
        or DEFAULT_LANGFLOW_BASE_URL
    ).rstrip("/")
    if configured.startswith("/"):
        return f"{base_url}{configured}"
    if configured.startswith("api/"):
        return f"{base_url}/{configured}"
    return f"{base_url}/api/v1/run/{configured}"


# 함수 설명: `_secret_text()`는 SecretStr 또는 일반 입력에서 노출 없이 실제 credential 문자열만 꺼냅니다.
def _secret_text(value: Any) -> str:
    getter = getattr(value, "get_secret_value", None)
    if callable(getter):
        return _clean(getter())
    return _clean(value)


# 함수 설명: `_safe_int()`는 예외를 발생시키지 않고 값을 정수로 바꾸며 허용되지 않는 값은 기본값으로 처리합니다.
def _safe_int(value: Any, default: int) -> int:
    try:
        return max(1, int(str(value or "").strip()))
    except Exception:
        return default


# 함수 설명: `_timeout_value()`는 호환 timeout 입력과 connect/read timeout을 requests가 요구하는 값으로 정규화합니다.
def _timeout_value(timeout_seconds: Any, connect_timeout_seconds: Any, read_timeout_seconds: Any) -> Any:
    if timeout_seconds not in (None, ""):
        return _safe_int(timeout_seconds, default=DEFAULT_READ_TIMEOUT_SECONDS)
    return (
        _safe_int(connect_timeout_seconds, default=DEFAULT_CONNECT_TIMEOUT_SECONDS),
        _safe_int(read_timeout_seconds, default=DEFAULT_READ_TIMEOUT_SECONDS),
    )


# 함수 설명: `_duration_ms()`는 시작 시각부터 현재까지의 API 호출 시간을 밀리초 정수로 계산합니다.
def _duration_ms(started: float) -> int:
    return max(0, int((time.monotonic() - started) * 1000))


# Langflow 컴포넌트 클래스: inputs/outputs가 캔버스 포트와 JSON edge 계약을 정의합니다.
# 실제 업무 규칙은 위의 주요 함수에 두어 UI 실행과 단위 테스트가 같은 로직을 사용합니다.
class FlowApiMessageCaller(Component):
    display_name = "01 선택 Flow API 메시지 호출기"
    description = "Smart Router가 선택한 branch의 원문 메시지를 하위 Langflow Run API로 전달하고, 하위 flow의 표시 메시지만 반환합니다."
    inputs = [
        MessageTextInput(name="flow_input", display_name="Flow 입력", required=True),
        MessageTextInput(
            name="api_url",
            display_name="하위 Flow endpoint/URL",
            value="",
            required=True,
            info="endpoint_name, /api/v1/run/... 경로 또는 전체 URL을 입력합니다. 상대값은 LANGFLOW_BASE_URL 기준으로 해석합니다.",
        ),
        SecretStrInput(name="api_key", display_name="Langflow API 키", value="", required=False, advanced=True),
        MessageTextInput(name="session_id", display_name="세션 ID", value="", required=False, advanced=True),
        MessageTextInput(name="route_name", display_name="Route 이름", value="", required=False, advanced=True),
        MessageTextInput(
            name="connect_timeout_seconds",
            display_name="연결 제한 시간(초)",
            value=str(DEFAULT_CONNECT_TIMEOUT_SECONDS),
            required=False,
            advanced=True,
        ),
        MessageTextInput(
            name="read_timeout_seconds",
            display_name="응답 제한 시간(초)",
            value=str(DEFAULT_READ_TIMEOUT_SECONDS),
            required=False,
            advanced=True,
        ),
    ]
    outputs = [
        Output(name="message", display_name="메시지", method="build_message", types=["Message"], group_outputs=True),
        Output(name="status_data", display_name="호출 상태", method="build_status", types=["Data"], group_outputs=True),
    ]

    # 함수 설명: `_run_once()`는 같은 Langflow 노드 실행에서 하위 Flow API가 중복 호출되지 않도록 결과를 한 번만 계산해 재사용합니다.
    def _run_once(self) -> dict[str, Any]:
        if not hasattr(self, "_cached_result"):
            session_id = getattr(self, "session_id", "")
            if not _clean(session_id):
                session_id = getattr(getattr(self, "graph", None), "session_id", "") or ""
            self._cached_result = run_flow_api_message(
                getattr(self, "flow_input", ""),
                api_url=getattr(self, "api_url", ""),
                api_key=getattr(self, "api_key", ""),
                session_id=session_id,
                connect_timeout_seconds=getattr(
                    self, "connect_timeout_seconds", str(DEFAULT_CONNECT_TIMEOUT_SECONDS)
                ),
                read_timeout_seconds=getattr(self, "read_timeout_seconds", str(DEFAULT_READ_TIMEOUT_SECONDS)),
                route_name=getattr(self, "route_name", ""),
            )
        return self._cached_result

    # Langflow 출력 함수: '메시지 (message)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_message(self) -> Message:
        result = self._run_once()
        return Message(text=_clean(result.get("message")))

    # Langflow 출력 함수: '호출 상태 (status_data)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_status(self) -> Data:
        result = self._run_once()
        return Data(
            data={
                "status": result.get("status"),
                "route_name": result.get("route_name"),
                "http_status": result.get("http_status"),
                "downstream_status": result.get("downstream_status"),
                "duration_ms": result.get("duration_ms"),
                "session_id": result.get("session_id"),
                "errors": result.get("errors", []),
                "warnings": result.get("warnings", []),
            }
        )

# -*- coding: utf-8 -*-
# =============================================================================
# 컴포넌트 개요: 01 선택 Flow API 메시지 호출기
# 역할: Smart Router가 선택한 branch의 원문 메시지를 하위 Langflow Run API로 전달하고, 하위 flow의 표시 메시지만 반환합니다.
# 주요 입력: Flow 입력 (flow_input) · 필수, 하위 Flow endpoint/URL (api_url) · 필수, Langflow API 키 (api_key), 세션 ID
#        (session_id), Route 이름 (route_name), 연결 제한 시간(초) (connect_timeout_seconds), 응답 제한 시간(초)
#        (read_timeout_seconds)
# 주요 출력: 메시지 (message), 호출 상태 (status_data)
# 처리 흐름: Smart Router가 선택한 하위 Flow Run API에 원문 질문과 부모 세션을 한 번만 전달하고 최종 Message를 추출합니다.
# 유지보수 포인트: nested child의 Chat 저장만 request tweak로 끄고 부모 Router가 세션 메시지를 한 번만 소유합니다.
# =============================================================================

from __future__ import annotations

import json
import os
import time
import uuid
from copy import deepcopy
from typing import Any

import requests
from lfx.custom.custom_component.component import Component
from lfx.io import MessageTextInput, Output, SecretStrInput
from lfx.schema.data import Data
from lfx.schema.message import Message

_HTTP_SESSION = requests.Session()
DEFAULT_LANGFLOW_BASE_URL = "http://127.0.0.1:7860"
DEFAULT_CONNECT_TIMEOUT_SECONDS = 5
DEFAULT_READ_TIMEOUT_SECONDS = 240
NESTED_CHAT_STORAGE_TWEAKS = {
    "Chat Input": {"should_store_message": False},
    "Chat Output": {"should_store_message": False},
}


# 주요 함수: 선택된 하위 Flow API를 호출하고 중간 출력이 아닌 최종 Message만 반환합니다.
# Langflow 클래스와 단위 테스트가 같은 업무 규칙을 쓰도록 일반 Python 값 중심으로 처리합니다.
def run_flow_api_message(
    flow_input_value: Any,
    *,
    api_url: str = "",
    api_key: str = "",
    session_id: str = "",
    session_source_value: Any = None,
    timeout_seconds: Any = None,
    connect_timeout_seconds: Any = DEFAULT_CONNECT_TIMEOUT_SECONDS,
    read_timeout_seconds: Any = DEFAULT_READ_TIMEOUT_SECONDS,
    route_name: str = "",
    post_func: Any = None,
) -> dict[str, Any]:
    flow_input = _input_text(flow_input_value, preserve=True)
    session_source = session_source_value if session_source_value is not None else flow_input_value
    session_id_value = _session_id(session_source, session_id)
    api_url_value = _resolve_api_url(api_url)
    warnings: list[dict[str, Any]] = []
    errors: list[dict[str, Any]] = []

    if not flow_input.strip():
        errors.append({"type": "empty_input", "message": "하위 flow로 전달할 입력이 비어 있습니다."})
    if _looks_like_route_message(flow_input):
        errors.append(
            {
                "type": "route_message_used_as_input",
                "message": (
                    "Smart Router Route Message가 사용자 질문 대신 전달되었습니다. "
                    "API 호출 route의 Route Message를 비우고 Smart Router route output이 원문을 그대로 보내도록 설정하세요."
                ),
            }
        )
    if not _clean(api_url):
        errors.append({"type": "missing_api_url", "message": "하위 flow의 Langflow Run API URL이 비어 있습니다."})

    if errors:
        return _message_result(
            status="error",
            message=_format_errors(errors),
            flow_input=flow_input,
            api_url=api_url_value,
            session_id=session_id_value,
            warnings=warnings,
            errors=errors,
            raw_response={},
            duration_ms=0,
            route_name=_clean(route_name),
        )

    request_body = {
        "input_value": flow_input,
        "input_type": "chat",
        "output_type": "chat",
        # Child Flow는 direct Playground 표시를 위해 저장을 기본 활성화합니다.
        # Router nested 호출에서만 display_name 기반 tweak로 child 질문/답변 저장을 끕니다.
        "tweaks": deepcopy(NESTED_CHAT_STORAGE_TWEAKS),
    }
    if session_id_value:
        request_body["session_id"] = session_id_value
    headers = {"Content-Type": "application/json"}
    api_key_value = _secret_text(api_key) or _clean(os.getenv("LANGFLOW_API_KEY", ""))
    if api_key_value:
        headers["x-api-key"] = api_key_value

    started = time.monotonic()
    post = post_func or _HTTP_SESSION.post
    timeout = _timeout_value(timeout_seconds, connect_timeout_seconds, read_timeout_seconds)
    try:
        response = post(api_url_value, json=request_body, headers=headers, timeout=timeout)
        http_status = int(getattr(response, "status_code", 200) or 200)
        raise_for_status = getattr(response, "raise_for_status", None)
        if callable(raise_for_status):
            raise_for_status()
        parsed = response.json() if callable(getattr(response, "json", None)) else response
    except Exception as exc:
        return _message_result(
            status="error",
            message=f"하위 flow API 호출에 실패했습니다: {exc}",
            flow_input=flow_input,
            api_url=api_url_value,
            session_id=session_id_value,
            warnings=warnings,
            errors=[{"type": "api_call_failed", "message": str(exc)}],
            raw_response={},
            duration_ms=_duration_ms(started),
            route_name=_clean(route_name),
        )

    raw_response = parsed if isinstance(parsed, dict) else {"response": parsed}
    message = _extract_message_text(raw_response)
    child_status = _extract_child_status(raw_response)
    child_failed = child_status in {"error", "failed", "failure"}
    if not message:
        message = "하위 flow가 표시 메시지를 반환하지 않았습니다."
        errors.append({"type": "missing_downstream_message", "message": message})
    result = _message_result(
        status="error" if child_failed or errors else "ok",
        message=message,
        flow_input=flow_input,
        api_url=api_url_value,
        session_id=session_id_value,
        warnings=warnings,
        errors=errors,
        raw_response=raw_response,
        duration_ms=_duration_ms(started),
        route_name=_clean(route_name),
    )
    result["request_body"] = request_body
    result["http_status"] = http_status
    result["downstream_status"] = child_status or "unknown"
    return result


# 함수 설명: `_message_result()`는 하위 Flow 호출 상태와 최종 Message를 Router 공통 결과 구조로 묶습니다.
def _message_result(
    *,
    status: str,
    message: str,
    flow_input: str,
    api_url: str,
    session_id: str,
    warnings: list[dict[str, Any]],
    errors: list[dict[str, Any]],
    raw_response: dict[str, Any],
    duration_ms: int,
    route_name: str,
) -> dict[str, Any]:
    return {
        "status": status,
        "message": message,
        "flow_input": flow_input,
        "api_url": api_url,
        "session_id": session_id,
        "warnings": warnings,
        "errors": errors,
        "raw_response": raw_response,
        "duration_ms": duration_ms,
        "route_name": route_name,
    }


# 함수 설명: `_looks_like_route_message()`는 입력값이 LIKE·라우팅·Message 조건에 해당하는지 부작용 없이 bool로 판정합니다.
def _looks_like_route_message(value: Any) -> bool:
    parsed = _parse_json_dict(str(value or ""))
    if not parsed:
        return False
    keys = {str(key) for key in parsed}
    return bool(keys & {"route", "selected_route", "route_name"}) and len(keys) <= 3


# 함수 설명: `_format_errors()`는 오류을 Markdown 또는 사용자 화면에서 안전하게 읽을 수 있는 표현으로 변환합니다.
def _format_errors(errors: list[dict[str, Any]]) -> str:
    return "\n".join(f"- {error.get('message', '')}" for error in errors if error.get("message"))


# 함수 설명: `_extract_message_text()`는 Langflow Run API의 중첩 응답에서 최종 사용자 Message 텍스트를 우선순위대로 찾습니다.
def _extract_message_text(value: Any) -> str:
    return _extract_message_text_inner(value, set())


# 함수 설명: `_extract_child_status()`는 하위 Flow 응답의 status를 여러 envelope 형식에서 우선순위대로 추출합니다.
def _extract_child_status(value: Any) -> str:
    if not isinstance(value, dict):
        return ""
    api_response = value.get("api_response")
    if isinstance(api_response, dict) and str(api_response.get("status") or "").strip():
        return str(api_response.get("status")).strip().lower()
    if str(value.get("status") or "").strip():
        return str(value.get("status")).strip().lower()
    for key in ("outputs", "results", "data", "artifacts"):
        nested = value.get(key)
        values = nested if isinstance(nested, list) else [nested]
        for item in values:
            status = _extract_child_status(item)
            if status:
                return status
    return ""


# 함수 설명: `_extract_message_text_inner()`는 복합 입력이나 응답에서 Message·문자열·inner을 찾아 검증 가능한 기본 Python 값으로 변환합니다.
def _extract_message_text_inner(value: Any, seen: set[int]) -> str:
    if value is None:
        return ""
    value_id = id(value)
    if value_id in seen:
        return ""
    seen.add(value_id)
    for attr in ("text", "content", "message"):
        text = getattr(value, attr, None)
        if isinstance(text, str) and text.strip():
            return text.strip()
    if isinstance(value, str):
        parsed = _parse_json_dict(value)
        if parsed:
            return _extract_message_text_inner(parsed, seen)
        return value.strip()
    if isinstance(value, dict):
        for key in ("api_response", "display_message", "answer_message", "answer", "text", "content", "output", "response", "message"):
            text = _extract_message_text_inner(value.get(key), seen)
            if text:
                return text
        for key in ("results", "artifacts", "outputs", "data", "messages"):
            text = _extract_message_text_inner(value.get(key), seen)
            if text:
                return text
    if isinstance(value, list):
        for item in value:
            text = _extract_message_text_inner(item, seen)
            if text:
                return text
    return ""


# 함수 설명: `_parse_json_dict()`는 복합 입력이나 응답에서 JSON·DICT을 찾아 검증 가능한 기본 Python 값으로 변환합니다.
def _parse_json_dict(value: str) -> dict[str, Any]:
    text = _clean(value)
    if not text:
        return {}
    if text.startswith("```"):
        text = text.strip("`").strip()
        if text.lower().startswith("json"):
            text = text[4:].strip()
    try:
        parsed = json.loads(text)
    except Exception:
        return {}
    return deepcopy(parsed) if isinstance(parsed, dict) else {}


# 함수 설명: `_input_text()`는 Message/Data/JSON 입력에서 하위 Flow에 그대로 전달할 원문 질문을 추출합니다.
def _input_text(value: Any, *, preserve: bool = False) -> str:
    if value is None:
        return ""
    for attr in ("text", "content", "message"):
        text = getattr(value, attr, None)
        if isinstance(text, str):
            return text if preserve else text.strip()
    if isinstance(value, str):
        return value if preserve else value.strip()
    data = getattr(value, "data", value)
    if isinstance(data, dict):
        for key in ("input_value", "question", "raw_text", "message", "text"):
            text = data.get(key)
            if isinstance(text, str):
                return text if preserve else text.strip()
    return ""


# 함수 설명: `_session_id()`는 명시 입력과 부모 Message의 session 정보를 우선순위대로 해석합니다.
def _session_id(source_value: Any, explicit_session_id: Any) -> str:
    explicit = _clean(explicit_session_id)
    if explicit:
        return explicit
    for attr in ("session_id", "sessionId"):
        candidate = getattr(source_value, attr, None)
        if _clean(candidate):
            return _clean(candidate)
    data = getattr(source_value, "data", source_value)
    if isinstance(data, dict):
        for key in ("session_id", "sessionId"):
            candidate = data.get(key)
            if _clean(candidate):
                return _clean(candidate)
        request = data.get("request")
        if isinstance(request, dict):
            candidate = request.get("session_id") or request.get("sessionId")
            if _clean(candidate):
                return _clean(candidate)
    if _input_text(source_value, preserve=False):
        return f"route_flow_{uuid.uuid4().hex}"
    return ""


# 함수 설명: `_clean()`는 선택 입력을 안전한 문자열로 바꾸고 불필요한 앞뒤 공백을 제거합니다.
def _clean(value: Any) -> str:
    if value is None:
        return ""
    return str(value).strip()


# 함수 설명: `_resolve_api_url()`는 여러 API·URL 후보와 우선순위를 검토해 실제 사용할 값을 확정합니다.
def _resolve_api_url(value: Any) -> str:
    configured = _clean(value)
    if not configured:
        return ""
    if configured.lower().startswith(("http://", "https://")):
        return configured
    base_url = (
        _clean(os.getenv("LANGFLOW_BASE_URL", ""))
        or _clean(os.getenv("LANGFLOW_API_BASE_URL", ""))
        or DEFAULT_LANGFLOW_BASE_URL
    ).rstrip("/")
    if configured.startswith("/"):
        return f"{base_url}{configured}"
    if configured.startswith("api/"):
        return f"{base_url}/{configured}"
    return f"{base_url}/api/v1/run/{configured}"


# 함수 설명: `_secret_text()`는 SecretStr 또는 일반 입력에서 노출 없이 실제 credential 문자열만 꺼냅니다.
def _secret_text(value: Any) -> str:
    getter = getattr(value, "get_secret_value", None)
    if callable(getter):
        return _clean(getter())
    return _clean(value)


# 함수 설명: `_safe_int()`는 예외를 발생시키지 않고 값을 정수로 바꾸며 허용되지 않는 값은 기본값으로 처리합니다.
def _safe_int(value: Any, default: int) -> int:
    try:
        return max(1, int(str(value or "").strip()))
    except Exception:
        return default


# 함수 설명: `_timeout_value()`는 호환 timeout 입력과 connect/read timeout을 requests가 요구하는 값으로 정규화합니다.
def _timeout_value(timeout_seconds: Any, connect_timeout_seconds: Any, read_timeout_seconds: Any) -> Any:
    if timeout_seconds not in (None, ""):
        return _safe_int(timeout_seconds, default=DEFAULT_READ_TIMEOUT_SECONDS)
    return (
        _safe_int(connect_timeout_seconds, default=DEFAULT_CONNECT_TIMEOUT_SECONDS),
        _safe_int(read_timeout_seconds, default=DEFAULT_READ_TIMEOUT_SECONDS),
    )


# 함수 설명: `_duration_ms()`는 시작 시각부터 현재까지의 API 호출 시간을 밀리초 정수로 계산합니다.
def _duration_ms(started: float) -> int:
    return max(0, int((time.monotonic() - started) * 1000))


# Langflow 컴포넌트 클래스: inputs/outputs가 캔버스 포트와 JSON edge 계약을 정의합니다.
# 실제 업무 규칙은 위의 주요 함수에 두어 UI 실행과 단위 테스트가 같은 로직을 사용합니다.
class FlowApiMessageCaller(Component):
    display_name = "01 선택 Flow API 메시지 호출기"
    description = "Smart Router가 선택한 branch의 원문 메시지를 하위 Langflow Run API로 전달하고, 하위 flow의 표시 메시지만 반환합니다."
    inputs = [
        MessageTextInput(name="flow_input", display_name="Flow 입력", required=True),
        MessageTextInput(
            name="api_url",
            display_name="하위 Flow endpoint/URL",
            value="",
            required=True,
            info="endpoint_name, /api/v1/run/... 경로 또는 전체 URL을 입력합니다. 상대값은 LANGFLOW_BASE_URL 기준으로 해석합니다.",
        ),
        SecretStrInput(name="api_key", display_name="Langflow API 키", value="", required=False, advanced=True),
        MessageTextInput(name="session_id", display_name="세션 ID", value="", required=False, advanced=True),
        MessageTextInput(name="route_name", display_name="Route 이름", value="", required=False, advanced=True),
        MessageTextInput(
            name="connect_timeout_seconds",
            display_name="연결 제한 시간(초)",
            value=str(DEFAULT_CONNECT_TIMEOUT_SECONDS),
            required=False,
            advanced=True,
        ),
        MessageTextInput(
            name="read_timeout_seconds",
            display_name="응답 제한 시간(초)",
            value=str(DEFAULT_READ_TIMEOUT_SECONDS),
            required=False,
            advanced=True,
        ),
    ]
    outputs = [
        Output(name="message", display_name="메시지", method="build_message", types=["Message"], group_outputs=True),
        Output(name="status_data", display_name="호출 상태", method="build_status", types=["Data"], group_outputs=True),
    ]

    # 함수 설명: `_run_once()`는 같은 Langflow 노드 실행에서 하위 Flow API가 중복 호출되지 않도록 결과를 한 번만 계산해 재사용합니다.
    def _run_once(self) -> dict[str, Any]:
        if not hasattr(self, "_cached_result"):
            session_id = getattr(self, "session_id", "")
            if not _clean(session_id):
                session_id = getattr(getattr(self, "graph", None), "session_id", "") or ""
            self._cached_result = run_flow_api_message(
                getattr(self, "flow_input", ""),
                api_url=getattr(self, "api_url", ""),
                api_key=getattr(self, "api_key", ""),
                session_id=session_id,
                connect_timeout_seconds=getattr(
                    self, "connect_timeout_seconds", str(DEFAULT_CONNECT_TIMEOUT_SECONDS)
                ),
                read_timeout_seconds=getattr(self, "read_timeout_seconds", str(DEFAULT_READ_TIMEOUT_SECONDS)),
                route_name=getattr(self, "route_name", ""),
            )
        return self._cached_result

    # Langflow 출력 함수: '메시지 (message)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_message(self) -> Message:
        result = self._run_once()
        return Message(text=_clean(result.get("message")))

    # Langflow 출력 함수: '호출 상태 (status_data)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_status(self) -> Data:
        result = self._run_once()
        return Data(
            data={
                "status": result.get("status"),
                "route_name": result.get("route_name"),
                "http_status": result.get("http_status"),
                "downstream_status": result.get("downstream_status"),
                "duration_ms": result.get("duration_ms"),
                "session_id": result.get("session_id"),
                "errors": result.get("errors", []),
                "warnings": result.get("warnings", []),
            }
        )

# -*- coding: utf-8 -*-
# =============================================================================
# 컴포넌트 개요: 01 선택 Flow API 메시지 호출기
# 역할: Smart Router가 선택한 branch의 원문 메시지를 하위 Langflow Run API로 전달하고, 하위 flow의 표시 메시지만 반환합니다.
# 주요 입력: Flow 입력 (flow_input) · 필수, 하위 Flow endpoint/URL (api_url) · 필수, Langflow API 키 (api_key), 세션 ID
#        (session_id), Route 이름 (route_name), 연결 제한 시간(초) (connect_timeout_seconds), 응답 제한 시간(초)
#        (read_timeout_seconds)
# 주요 출력: 메시지 (message), 호출 상태 (status_data)
# 처리 흐름: Smart Router가 선택한 하위 Flow Run API에 원문 질문과 부모 세션을 한 번만 전달하고 최종 Message를 추출합니다.
# 유지보수 포인트: nested child의 Chat 저장만 request tweak로 끄고 부모 Router가 세션 메시지를 한 번만 소유합니다.
# =============================================================================

from __future__ import annotations

import json
import os
import time
import uuid
from copy import deepcopy
from typing import Any

import requests
from lfx.custom.custom_component.component import Component
from lfx.io import MessageTextInput, Output, SecretStrInput
from lfx.schema.data import Data
from lfx.schema.message import Message

_HTTP_SESSION = requests.Session()
DEFAULT_LANGFLOW_BASE_URL = "http://127.0.0.1:7860"
DEFAULT_CONNECT_TIMEOUT_SECONDS = 5
DEFAULT_READ_TIMEOUT_SECONDS = 240
NESTED_CHAT_STORAGE_TWEAKS = {
    "Chat Input": {"should_store_message": False},
    "Chat Output": {"should_store_message": False},
}


# 주요 함수: 선택된 하위 Flow API를 호출하고 중간 출력이 아닌 최종 Message만 반환합니다.
# Langflow 클래스와 단위 테스트가 같은 업무 규칙을 쓰도록 일반 Python 값 중심으로 처리합니다.
def run_flow_api_message(
    flow_input_value: Any,
    *,
    api_url: str = "",
    api_key: str = "",
    session_id: str = "",
    session_source_value: Any = None,
    timeout_seconds: Any = None,
    connect_timeout_seconds: Any = DEFAULT_CONNECT_TIMEOUT_SECONDS,
    read_timeout_seconds: Any = DEFAULT_READ_TIMEOUT_SECONDS,
    route_name: str = "",
    post_func: Any = None,
) -> dict[str, Any]:
    flow_input = _input_text(flow_input_value, preserve=True)
    session_source = session_source_value if session_source_value is not None else flow_input_value
    session_id_value = _session_id(session_source, session_id)
    api_url_value = _resolve_api_url(api_url)
    warnings: list[dict[str, Any]] = []
    errors: list[dict[str, Any]] = []

    if not flow_input.strip():
        errors.append({"type": "empty_input", "message": "하위 flow로 전달할 입력이 비어 있습니다."})
    if _looks_like_route_message(flow_input):
        errors.append(
            {
                "type": "route_message_used_as_input",
                "message": (
                    "Smart Router Route Message가 사용자 질문 대신 전달되었습니다. "
                    "API 호출 route의 Route Message를 비우고 Smart Router route output이 원문을 그대로 보내도록 설정하세요."
                ),
            }
        )
    if not _clean(api_url):
        errors.append({"type": "missing_api_url", "message": "하위 flow의 Langflow Run API URL이 비어 있습니다."})

    if errors:
        return _message_result(
            status="error",
            message=_format_errors(errors),
            flow_input=flow_input,
            api_url=api_url_value,
            session_id=session_id_value,
            warnings=warnings,
            errors=errors,
            raw_response={},
            duration_ms=0,
            route_name=_clean(route_name),
        )

    request_body = {
        "input_value": flow_input,
        "input_type": "chat",
        "output_type": "chat",
        # Child Flow는 direct Playground 표시를 위해 저장을 기본 활성화합니다.
        # Router nested 호출에서만 display_name 기반 tweak로 child 질문/답변 저장을 끕니다.
        "tweaks": deepcopy(NESTED_CHAT_STORAGE_TWEAKS),
    }
    if session_id_value:
        request_body["session_id"] = session_id_value
    headers = {"Content-Type": "application/json"}
    api_key_value = _secret_text(api_key) or _clean(os.getenv("LANGFLOW_API_KEY", ""))
    if api_key_value:
        headers["x-api-key"] = api_key_value

    started = time.monotonic()
    post = post_func or _HTTP_SESSION.post
    timeout = _timeout_value(timeout_seconds, connect_timeout_seconds, read_timeout_seconds)
    try:
        response = post(api_url_value, json=request_body, headers=headers, timeout=timeout)
        http_status = int(getattr(response, "status_code", 200) or 200)
        raise_for_status = getattr(response, "raise_for_status", None)
        if callable(raise_for_status):
            raise_for_status()
        parsed = response.json() if callable(getattr(response, "json", None)) else response
    except Exception as exc:
        return _message_result(
            status="error",
            message=f"하위 flow API 호출에 실패했습니다: {exc}",
            flow_input=flow_input,
            api_url=api_url_value,
            session_id=session_id_value,
            warnings=warnings,
            errors=[{"type": "api_call_failed", "message": str(exc)}],
            raw_response={},
            duration_ms=_duration_ms(started),
            route_name=_clean(route_name),
        )

    raw_response = parsed if isinstance(parsed, dict) else {"response": parsed}
    message = _extract_message_text(raw_response)
    child_status = _extract_child_status(raw_response)
    child_failed = child_status in {"error", "failed", "failure"}
    if not message:
        message = "하위 flow가 표시 메시지를 반환하지 않았습니다."
        errors.append({"type": "missing_downstream_message", "message": message})
    result = _message_result(
        status="error" if child_failed or errors else "ok",
        message=message,
        flow_input=flow_input,
        api_url=api_url_value,
        session_id=session_id_value,
        warnings=warnings,
        errors=errors,
        raw_response=raw_response,
        duration_ms=_duration_ms(started),
        route_name=_clean(route_name),
    )
    result["request_body"] = request_body
    result["http_status"] = http_status
    result["downstream_status"] = child_status or "unknown"
    return result


# 함수 설명: `_message_result()`는 하위 Flow 호출 상태와 최종 Message를 Router 공통 결과 구조로 묶습니다.
def _message_result(
    *,
    status: str,
    message: str,
    flow_input: str,
    api_url: str,
    session_id: str,
    warnings: list[dict[str, Any]],
    errors: list[dict[str, Any]],
    raw_response: dict[str, Any],
    duration_ms: int,
    route_name: str,
) -> dict[str, Any]:
    return {
        "status": status,
        "message": message,
        "flow_input": flow_input,
        "api_url": api_url,
        "session_id": session_id,
        "warnings": warnings,
        "errors": errors,
        "raw_response": raw_response,
        "duration_ms": duration_ms,
        "route_name": route_name,
    }


# 함수 설명: `_looks_like_route_message()`는 입력값이 LIKE·라우팅·Message 조건에 해당하는지 부작용 없이 bool로 판정합니다.
def _looks_like_route_message(value: Any) -> bool:
    parsed = _parse_json_dict(str(value or ""))
    if not parsed:
        return False
    keys = {str(key) for key in parsed}
    return bool(keys & {"route", "selected_route", "route_name"}) and len(keys) <= 3


# 함수 설명: `_format_errors()`는 오류을 Markdown 또는 사용자 화면에서 안전하게 읽을 수 있는 표현으로 변환합니다.
def _format_errors(errors: list[dict[str, Any]]) -> str:
    return "\n".join(f"- {error.get('message', '')}" for error in errors if error.get("message"))


# 함수 설명: `_extract_message_text()`는 Langflow Run API의 중첩 응답에서 최종 사용자 Message 텍스트를 우선순위대로 찾습니다.
def _extract_message_text(value: Any) -> str:
    return _extract_message_text_inner(value, set())


# 함수 설명: `_extract_child_status()`는 하위 Flow 응답의 status를 여러 envelope 형식에서 우선순위대로 추출합니다.
def _extract_child_status(value: Any) -> str:
    if not isinstance(value, dict):
        return ""
    api_response = value.get("api_response")
    if isinstance(api_response, dict) and str(api_response.get("status") or "").strip():
        return str(api_response.get("status")).strip().lower()
    if str(value.get("status") or "").strip():
        return str(value.get("status")).strip().lower()
    for key in ("outputs", "results", "data", "artifacts"):
        nested = value.get(key)
        values = nested if isinstance(nested, list) else [nested]
        for item in values:
            status = _extract_child_status(item)
            if status:
                return status
    return ""


# 함수 설명: `_extract_message_text_inner()`는 복합 입력이나 응답에서 Message·문자열·inner을 찾아 검증 가능한 기본 Python 값으로 변환합니다.
def _extract_message_text_inner(value: Any, seen: set[int]) -> str:
    if value is None:
        return ""
    value_id = id(value)
    if value_id in seen:
        return ""
    seen.add(value_id)
    for attr in ("text", "content", "message"):
        text = getattr(value, attr, None)
        if isinstance(text, str) and text.strip():
            return text.strip()
    if isinstance(value, str):
        parsed = _parse_json_dict(value)
        if parsed:
            return _extract_message_text_inner(parsed, seen)
        return value.strip()
    if isinstance(value, dict):
        for key in ("api_response", "display_message", "answer_message", "answer", "text", "content", "output", "response", "message"):
            text = _extract_message_text_inner(value.get(key), seen)
            if text:
                return text
        for key in ("results", "artifacts", "outputs", "data", "messages"):
            text = _extract_message_text_inner(value.get(key), seen)
            if text:
                return text
    if isinstance(value, list):
        for item in value:
            text = _extract_message_text_inner(item, seen)
            if text:
                return text
    return ""


# 함수 설명: `_parse_json_dict()`는 복합 입력이나 응답에서 JSON·DICT을 찾아 검증 가능한 기본 Python 값으로 변환합니다.
def _parse_json_dict(value: str) -> dict[str, Any]:
    text = _clean(value)
    if not text:
        return {}
    if text.startswith("```"):
        text = text.strip("`").strip()
        if text.lower().startswith("json"):
            text = text[4:].strip()
    try:
        parsed = json.loads(text)
    except Exception:
        return {}
    return deepcopy(parsed) if isinstance(parsed, dict) else {}


# 함수 설명: `_input_text()`는 Message/Data/JSON 입력에서 하위 Flow에 그대로 전달할 원문 질문을 추출합니다.
def _input_text(value: Any, *, preserve: bool = False) -> str:
    if value is None:
        return ""
    for attr in ("text", "content", "message"):
        text = getattr(value, attr, None)
        if isinstance(text, str):
            return text if preserve else text.strip()
    if isinstance(value, str):
        return value if preserve else value.strip()
    data = getattr(value, "data", value)
    if isinstance(data, dict):
        for key in ("input_value", "question", "raw_text", "message", "text"):
            text = data.get(key)
            if isinstance(text, str):
                return text if preserve else text.strip()
    return ""


# 함수 설명: `_session_id()`는 명시 입력과 부모 Message의 session 정보를 우선순위대로 해석합니다.
def _session_id(source_value: Any, explicit_session_id: Any) -> str:
    explicit = _clean(explicit_session_id)
    if explicit:
        return explicit
    for attr in ("session_id", "sessionId"):
        candidate = getattr(source_value, attr, None)
        if _clean(candidate):
            return _clean(candidate)
    data = getattr(source_value, "data", source_value)
    if isinstance(data, dict):
        for key in ("session_id", "sessionId"):
            candidate = data.get(key)
            if _clean(candidate):
                return _clean(candidate)
        request = data.get("request")
        if isinstance(request, dict):
            candidate = request.get("session_id") or request.get("sessionId")
            if _clean(candidate):
                return _clean(candidate)
    if _input_text(source_value, preserve=False):
        return f"route_flow_{uuid.uuid4().hex}"
    return ""


# 함수 설명: `_clean()`는 선택 입력을 안전한 문자열로 바꾸고 불필요한 앞뒤 공백을 제거합니다.
def _clean(value: Any) -> str:
    if value is None:
        return ""
    return str(value).strip()


# 함수 설명: `_resolve_api_url()`는 여러 API·URL 후보와 우선순위를 검토해 실제 사용할 값을 확정합니다.
def _resolve_api_url(value: Any) -> str:
    configured = _clean(value)
    if not configured:
        return ""
    if configured.lower().startswith(("http://", "https://")):
        return configured
    base_url = (
        _clean(os.getenv("LANGFLOW_BASE_URL", ""))
        or _clean(os.getenv("LANGFLOW_API_BASE_URL", ""))
        or DEFAULT_LANGFLOW_BASE_URL
    ).rstrip("/")
    if configured.startswith("/"):
        return f"{base_url}{configured}"
    if configured.startswith("api/"):
        return f"{base_url}/{configured}"
    return f"{base_url}/api/v1/run/{configured}"


# 함수 설명: `_secret_text()`는 SecretStr 또는 일반 입력에서 노출 없이 실제 credential 문자열만 꺼냅니다.
def _secret_text(value: Any) -> str:
    getter = getattr(value, "get_secret_value", None)
    if callable(getter):
        return _clean(getter())
    return _clean(value)


# 함수 설명: `_safe_int()`는 예외를 발생시키지 않고 값을 정수로 바꾸며 허용되지 않는 값은 기본값으로 처리합니다.
def _safe_int(value: Any, default: int) -> int:
    try:
        return max(1, int(str(value or "").strip()))
    except Exception:
        return default


# 함수 설명: `_timeout_value()`는 호환 timeout 입력과 connect/read timeout을 requests가 요구하는 값으로 정규화합니다.
def _timeout_value(timeout_seconds: Any, connect_timeout_seconds: Any, read_timeout_seconds: Any) -> Any:
    if timeout_seconds not in (None, ""):
        return _safe_int(timeout_seconds, default=DEFAULT_READ_TIMEOUT_SECONDS)
    return (
        _safe_int(connect_timeout_seconds, default=DEFAULT_CONNECT_TIMEOUT_SECONDS),
        _safe_int(read_timeout_seconds, default=DEFAULT_READ_TIMEOUT_SECONDS),
    )


# 함수 설명: `_duration_ms()`는 시작 시각부터 현재까지의 API 호출 시간을 밀리초 정수로 계산합니다.
def _duration_ms(started: float) -> int:
    return max(0, int((time.monotonic() - started) * 1000))


# Langflow 컴포넌트 클래스: inputs/outputs가 캔버스 포트와 JSON edge 계약을 정의합니다.
# 실제 업무 규칙은 위의 주요 함수에 두어 UI 실행과 단위 테스트가 같은 로직을 사용합니다.
class FlowApiMessageCaller(Component):
    display_name = "01 선택 Flow API 메시지 호출기"
    description = "Smart Router가 선택한 branch의 원문 메시지를 하위 Langflow Run API로 전달하고, 하위 flow의 표시 메시지만 반환합니다."
    inputs = [
        MessageTextInput(name="flow_input", display_name="Flow 입력", required=True),
        MessageTextInput(
            name="api_url",
            display_name="하위 Flow endpoint/URL",
            value="",
            required=True,
            info="endpoint_name, /api/v1/run/... 경로 또는 전체 URL을 입력합니다. 상대값은 LANGFLOW_BASE_URL 기준으로 해석합니다.",
        ),
        SecretStrInput(name="api_key", display_name="Langflow API 키", value="", required=False, advanced=True),
        MessageTextInput(name="session_id", display_name="세션 ID", value="", required=False, advanced=True),
        MessageTextInput(name="route_name", display_name="Route 이름", value="", required=False, advanced=True),
        MessageTextInput(
            name="connect_timeout_seconds",
            display_name="연결 제한 시간(초)",
            value=str(DEFAULT_CONNECT_TIMEOUT_SECONDS),
            required=False,
            advanced=True,
        ),
        MessageTextInput(
            name="read_timeout_seconds",
            display_name="응답 제한 시간(초)",
            value=str(DEFAULT_READ_TIMEOUT_SECONDS),
            required=False,
            advanced=True,
        ),
    ]
    outputs = [
        Output(name="message", display_name="메시지", method="build_message", types=["Message"], group_outputs=True),
        Output(name="status_data", display_name="호출 상태", method="build_status", types=["Data"], group_outputs=True),
    ]

    # 함수 설명: `_run_once()`는 같은 Langflow 노드 실행에서 하위 Flow API가 중복 호출되지 않도록 결과를 한 번만 계산해 재사용합니다.
    def _run_once(self) -> dict[str, Any]:
        if not hasattr(self, "_cached_result"):
            session_id = getattr(self, "session_id", "")
            if not _clean(session_id):
                session_id = getattr(getattr(self, "graph", None), "session_id", "") or ""
            self._cached_result = run_flow_api_message(
                getattr(self, "flow_input", ""),
                api_url=getattr(self, "api_url", ""),
                api_key=getattr(self, "api_key", ""),
                session_id=session_id,
                connect_timeout_seconds=getattr(
                    self, "connect_timeout_seconds", str(DEFAULT_CONNECT_TIMEOUT_SECONDS)
                ),
                read_timeout_seconds=getattr(self, "read_timeout_seconds", str(DEFAULT_READ_TIMEOUT_SECONDS)),
                route_name=getattr(self, "route_name", ""),
            )
        return self._cached_result

    # Langflow 출력 함수: '메시지 (message)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_message(self) -> Message:
        result = self._run_once()
        return Message(text=_clean(result.get("message")))

    # Langflow 출력 함수: '호출 상태 (status_data)' 포트가 요청될 때 실행됩니다.
    # 핵심 처리 결과를 Langflow Data/Message 형식으로 감싸 다음 노드에 전달합니다.
    def build_status(self) -> Data:
        result = self._run_once()
        return Data(
            data={
                "status": result.get("status"),
                "route_name": result.get("route_name"),
                "http_status": result.get("http_status"),
                "downstream_status": result.get("downstream_status"),
                "duration_ms": result.get("duration_ms"),
                "session_id": result.get("session_id"),
                "errors": result.get("errors", []),
                "warnings": result.get("warnings", []),
            }
        )

