# -*- coding: utf-8 -*-
# =============================================================================
# 컴포넌트 개요: 04 Workflow Skill 등록 결과 정규화기
# 역할: LLM 후보 JSON을 저장 가능한 Workflow Skill 문서로 정규화하고 실행 계약을 결정론적으로 검증합니다.
# 주요 입력: 요청 페이로드(payload), LLM 응답(llm_response)
# 주요 출력: 페이로드 출력(payload_out)
# 처리 흐름: JSON 파싱 -> 필드 정규화 -> Tool·단계·dependency·handoff 검증 -> 저장 후보 생성
# 유지보수 포인트: LLM 출력이 규칙을 위반하면 자동 보정으로 숨기지 않고 errors에 기록해 Writer에서 차단합니다.
# =============================================================================

from __future__ import annotations

import json
import re
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, MessageTextInput, Output
from lfx.schema.data import Data

SECTION = "workflow_skills"
MAX_STEPS = 4
MAX_STEP_QUESTION_CHARS = 4000
MAX_WORKFLOW_PAYLOAD_BYTES = 32768
WORKFLOW_KEY_PATTERN = re.compile(r"^[a-z][a-z0-9_-]{2,63}$")
STEP_ID_PATTERN = re.compile(r"^[A-Za-z][A-Za-z0-9_-]{0,63}$")
ALLOWED_TOOL_NAMES = {
    "run_data_analysis",
    "run_metadata_qa",
    "run_visualization",
    "save_domain_metadata",
    "save_table_catalog_metadata",
    "save_main_flow_filter_metadata",
}
ALLOWED_HANDOFFS = {"none", "result_ref"}
ALLOWED_ON_ERROR = {"stop", "continue"}
RESULT_REF_PRODUCERS = {"run_data_analysis"}
RESULT_REF_CONSUMERS = {"run_data_analysis", "run_visualization"}


# 주요 함수: LLM 응답에서 Workflow Skill 후보 하나를 추출하고 모든 실행 규칙 위반을 오류로 기록합니다.
def normalize_authoring(payload_value: Any, llm_response: Any) -> dict[str, Any]:
    payload = _payload(payload_value)
    parsed = _json(llm_response)
    raw_items = _raw_items(parsed)
    errors = []
    if not parsed:
        errors.append({"type": "llm_response_parse_error", "message": "LLM 등록 응답을 JSON object로 해석하지 못했습니다."})
    if len(raw_items) > 1:
        errors.append({"type": "multiple_workflows_not_allowed", "message": "한 요청에서는 Workflow Skill을 한 건만 등록할 수 있습니다."})
    items = []
    for index, raw in enumerate(raw_items[:1]):
        if not isinstance(raw, dict):
            errors.append({"type": "invalid_workflow_item", "message": f"items[{index}]가 object가 아닙니다.", "index": index})
            continue
        item = _normalize_item(raw)
        errors.extend(validate_workflow_item(item, index))
        items.append(item)
    refinement = _refinement(payload, parsed)
    if not items and not refinement["needs_more_input"] and not errors:
        errors.append({"type": "no_valid_workflow", "message": "저장할 Workflow Skill 후보가 생성되지 않았습니다."})
    payload["items"] = items
    payload["refinement"] = refinement
    payload.setdefault("errors", []).extend(errors)
    payload.setdefault("trace", {})["generated_items_preview"] = [
        {
            "key": str(item.get("key") or ""),
            "display_name": str(_dict(item.get("payload")).get("display_name") or ""),
            "step_count": len(_list(_dict(item.get("payload")).get("steps"))),
            "tool_names": [str(_dict(step).get("tool_name") or "") for step in _list(_dict(item.get("payload")).get("steps"))],
        }
        for item in items
    ]
    payload["trace"]["workflow_contract"] = {
        "max_steps": MAX_STEPS,
        "allowed_tools": sorted(ALLOWED_TOOL_NAMES),
        "result_ref_producers": sorted(RESULT_REF_PRODUCERS),
        "result_ref_consumers": sorted(RESULT_REF_CONSUMERS),
    }
    return payload


# 주요 함수: 정규화된 Workflow Skill의 필수 필드와 순차 실행 계약을 결정론적으로 검사합니다.
def validate_workflow_item(item: dict[str, Any], item_index: int = 0) -> list[dict[str, Any]]:
    errors: list[dict[str, Any]] = []
    key = str(item.get("key") or "")
    item_payload = _dict(item.get("payload"))
    steps = [_dict(step) for step in _list(item_payload.get("steps"))]
    if item.get("section") != SECTION:
        errors.append(_issue("invalid_section", f"section은 {SECTION}이어야 합니다.", item_index=item_index, key=key))
    if not WORKFLOW_KEY_PATTERN.fullmatch(key):
        errors.append(_issue("invalid_workflow_key", "workflow key는 영문 소문자로 시작하는 3~64자의 영문 소문자·숫자·밑줄·하이픈이어야 합니다.", item_index=item_index, key=key))
    if not str(item_payload.get("display_name") or "").strip():
        errors.append(_issue("missing_display_name", "Workflow 표시 이름이 없습니다.", item_index=item_index, key=key))
    if not str(item_payload.get("description") or "").strip():
        errors.append(_issue("missing_description", "Workflow 설명이 없습니다.", item_index=item_index, key=key))
    if not steps:
        errors.append(_issue("missing_steps", "Workflow에는 실행 단계가 한 개 이상 필요합니다.", item_index=item_index, key=key))
    if len(steps) > MAX_STEPS:
        errors.append(_issue("too_many_steps", f"Workflow 실행 단계는 최대 {MAX_STEPS}개입니다.", item_index=item_index, key=key, step_count=len(steps)))
    seen_step_ids: set[str] = set()
    step_by_id: dict[str, dict[str, Any]] = {}
    for step_index, step in enumerate(steps):
        step_id = str(step.get("step_id") or "")
        tool_name = str(step.get("tool_name") or "")
        depends_on = [str(value) for value in _list(step.get("depends_on"))]
        handoff = str(step.get("handoff") or "")
        location = {"item_index": item_index, "key": key, "step_index": step_index, "step_id": step_id}
        if not STEP_ID_PATTERN.fullmatch(step_id):
            errors.append(_issue("invalid_step_id", "step_id는 영문자로 시작하는 1~64자의 영문·숫자·밑줄·하이픈이어야 합니다.", **location))
        if step_id in seen_step_ids:
            errors.append(_issue("duplicate_step_id", "같은 Workflow 안에서 step_id가 중복되었습니다.", **location))
        if tool_name not in ALLOWED_TOOL_NAMES:
            errors.append(_issue("unsupported_tool", f"지원하지 않는 Tool입니다: {tool_name}", **location))
        question = str(step.get("question") or "").strip()
        if not question:
            errors.append(_issue("missing_step_question", "각 단계에는 실행할 question이 필요합니다.", **location))
        elif len(question) > MAX_STEP_QUESTION_CHARS:
            errors.append(_issue("step_question_too_long", f"단계 question은 {MAX_STEP_QUESTION_CHARS}자를 초과할 수 없습니다.", **location))
        if handoff not in ALLOWED_HANDOFFS:
            errors.append(_issue("invalid_handoff", "handoff는 none 또는 result_ref여야 합니다.", **location))
        if str(step.get("on_error") or "") not in ALLOWED_ON_ERROR:
            errors.append(_issue("invalid_on_error", "on_error는 stop 또는 continue여야 합니다.", **location))
        if len(depends_on) != len(set(depends_on)):
            errors.append(_issue("duplicate_dependency", "depends_on에 같은 step_id가 중복되었습니다.", **location))
        for dependency in depends_on:
            if dependency not in seen_step_ids:
                errors.append(_issue("dependency_not_prior", f"depends_on은 앞에서 정의된 step_id만 사용할 수 있습니다: {dependency}", dependency=dependency, **location))
        if step_index == 0 and depends_on:
            errors.append(_issue("first_step_dependency_not_allowed", "첫 단계의 depends_on은 빈 배열이어야 합니다.", **location))
        if step_index == 0 and handoff != "none":
            errors.append(_issue("first_step_handoff_not_allowed", "첫 단계의 handoff는 none이어야 합니다.", **location))
        if handoff == "result_ref":
            if len(depends_on) != 1:
                errors.append(_issue("ambiguous_result_ref_handoff", "result_ref handoff에는 dependency가 정확히 한 개 필요합니다.", **location))
            elif depends_on[0] in step_by_id:
                source_tool = str(step_by_id[depends_on[0]].get("tool_name") or "")
                if source_tool not in RESULT_REF_PRODUCERS:
                    errors.append(_issue("result_ref_source_not_supported", f"{source_tool}은 result_ref를 생성하지 않습니다.", dependency=depends_on[0], **location))
            if tool_name not in RESULT_REF_CONSUMERS:
                errors.append(_issue("result_ref_target_not_supported", f"{tool_name}은 upstream_result_ref 입력을 지원하지 않습니다.", **location))
        seen_step_ids.add(step_id)
        step_by_id[step_id] = step
    payload_bytes = len(json.dumps(item_payload, ensure_ascii=False, separators=(",", ":")).encode("utf-8"))
    if payload_bytes > MAX_WORKFLOW_PAYLOAD_BYTES:
        errors.append(
            _issue(
                "workflow_payload_too_large",
                f"Workflow Skill payload는 UTF-8 {MAX_WORKFLOW_PAYLOAD_BYTES}바이트를 초과할 수 없습니다.",
                item_index=item_index,
                key=key,
                payload_bytes=payload_bytes,
            )
        )
    return _unique_errors(errors)


# 함수 설명: `_raw_items()`는 허용된 LLM 응답 변형에서 Workflow 후보 목록을 꺼냅니다.
def _raw_items(parsed: dict[str, Any]) -> list[Any]:
    if isinstance(parsed.get("items"), list):
        return parsed["items"]
    if isinstance(parsed.get("workflow"), dict):
        return [parsed["workflow"]]
    if isinstance(parsed.get("workflows"), list):
        return parsed["workflows"]
    if parsed.get("workflow_key") or parsed.get("key"):
        return [parsed]
    return []


# 함수 설명: `_normalize_item()`은 LLM의 여러 필드 별칭을 고정된 MongoDB Workflow Skill 문서 형태로 바꿉니다.
def _normalize_item(raw: dict[str, Any]) -> dict[str, Any]:
    raw_payload = _dict(raw.get("payload"))
    key = _text(raw.get("key") or raw.get("workflow_key") or raw_payload.get("workflow_key"))
    display_name = _text(raw_payload.get("display_name") or raw_payload.get("title") or raw.get("display_name") or raw.get("title"))
    description = _text(raw_payload.get("description") or raw.get("description"))
    steps_source = raw_payload.get("steps") if isinstance(raw_payload.get("steps"), list) else raw.get("steps")
    steps = [_normalize_step(step, index) for index, step in enumerate(_list(steps_source)) if isinstance(step, dict)]
    return {
        "section": SECTION,
        "key": key,
        "status": "inactive" if str(raw.get("status") or "").strip().lower() == "inactive" else "active",
        "payload": {
            "display_name": display_name,
            "description": description,
            "aliases": _string_list(raw_payload.get("aliases") or raw.get("aliases"), 20, 120),
            "intent_examples": _string_list(raw_payload.get("intent_examples") or raw.get("intent_examples"), 20, 500),
            "keywords": _string_list(raw_payload.get("keywords") or raw.get("keywords"), 30, 80),
            "excluded_keywords": _string_list(raw_payload.get("excluded_keywords") or raw.get("excluded_keywords"), 30, 80),
            "priority": _bounded_int(raw_payload.get("priority", raw.get("priority", 100)), 100, -1000, 1000),
            "steps": steps,
        },
    }


# 함수 설명: `_normalize_step()`은 단계 필드를 08 Workflow Orchestrator가 소비하는 고정 step 계약으로 변환합니다.
def _normalize_step(raw: dict[str, Any], index: int) -> dict[str, Any]:
    del index
    dependencies = raw.get("depends_on")
    if isinstance(dependencies, str):
        dependencies = [dependencies]
    return {
        "step_id": _text(raw.get("step_id") or raw.get("id")),
        "tool_name": _text(raw.get("tool_name") or raw.get("tool")).lower(),
        "question": _text(raw.get("question")),
        "depends_on": _string_list(dependencies, MAX_STEPS, 64),
        "handoff": _text(raw.get("handoff") or "none").lower(),
        "on_error": _text(raw.get("on_error") or "stop").lower(),
    }


# 함수 설명: `_refinement()`은 LLM의 보완 필요 정보와 기존 보정 상태를 손실 없이 합칩니다.
def _refinement(payload: dict[str, Any], parsed: dict[str, Any]) -> dict[str, Any]:
    current = deepcopy(_dict(payload.get("refinement")))
    supplied = _dict(parsed.get("refinement"))
    missing = _string_list(supplied.get("missing_information") or parsed.get("missing_information"), 20, 500)
    assumptions = _string_list(supplied.get("assumptions") or parsed.get("assumptions"), 20, 500)
    return {
        "refined_text": _text(supplied.get("refined_text") or current.get("refined_text")),
        "needs_more_input": _truthy(supplied.get("needs_more_input", parsed.get("needs_more_input"))) or bool(missing),
        "missing_information": missing,
        "assumptions": assumptions,
    }


# 함수 설명: `_issue()`는 검증 오류를 type·message와 위치 정보가 있는 표준 dict로 만듭니다.
def _issue(error_type: str, message: str, **details: Any) -> dict[str, Any]:
    return {"type": error_type, "message": message, **details}


# 함수 설명: `_unique_errors()`는 같은 위치에서 반복된 오류를 최초 순서대로 하나만 남깁니다.
def _unique_errors(values: list[dict[str, Any]]) -> list[dict[str, Any]]:
    result = []
    seen = set()
    for value in values:
        marker = (value.get("type"), value.get("key"), value.get("step_id"), value.get("dependency"), value.get("message"))
        if marker not in seen:
            seen.add(marker)
            result.append(value)
    return result


# 함수 설명: `_string_list()`는 문자열 목록을 공백·중복·길이 제한이 적용된 안전한 목록으로 정리합니다.
def _string_list(value: Any, item_limit: int, text_limit: int) -> list[str]:
    raw = value if isinstance(value, list) else []
    result = []
    seen = set()
    for item in raw:
        text = _text(item)
        text = text[:text_limit]
        marker = text.casefold()
        if text and marker not in seen:
            seen.add(marker)
            result.append(text)
        if len(result) >= item_limit:
            break
    return result


# 함수 설명: `_bounded_int()`는 priority 값을 허용 범위 안의 정수로 제한합니다.
def _bounded_int(value: Any, default: int, minimum: int, maximum: int) -> int:
    try:
        return max(minimum, min(maximum, int(value)))
    except Exception:
        return default


# 함수 설명: `_truthy()`는 LLM의 bool 또는 문자열 표현을 안전한 참·거짓 값으로 해석합니다.
def _truthy(value: Any) -> bool:
    return value is True or str(value or "").strip().lower() in {"1", "true", "yes", "y", "on"}


# 함수 설명: `_text()`는 Message 또는 일반 값을 앞뒤 공백이 없는 문자열로 변환합니다.
def _text(value: Any) -> str:
    text = getattr(value, "text", value)
    return "" if text is None else str(text).strip()


# 함수 설명: `_payload()`는 Langflow Data 또는 dict에서 후속 변경에 안전한 복사본을 꺼냅니다.
def _payload(value: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    return deepcopy(data) if isinstance(data, dict) else {}


# 함수 설명: `_json()`은 Message·dict·Markdown JSON 응답에서 object 하나를 안전하게 파싱합니다.
def _json(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return deepcopy(value)
    text = _text(value)
    fence = re.search(r"```(?:json)?\s*(\{.*\})\s*```", text, re.DOTALL | re.IGNORECASE)
    if fence:
        text = fence.group(1)
    elif "{" in text and "}" in text:
        text = text[text.find("{") : text.rfind("}") + 1]
    try:
        parsed = json.loads(text)
    except Exception:
        return {}
    return parsed if isinstance(parsed, dict) else {}


# 함수 설명: `_dict()`는 값이 dict일 때만 그대로 반환하고 다른 형식은 빈 dict로 바꿉니다.
def _dict(value: Any) -> dict[str, Any]:
    return value if isinstance(value, dict) else {}


# 함수 설명: `_list()`는 값이 list일 때만 그대로 반환하고 다른 형식은 빈 목록으로 바꿉니다.
def _list(value: Any) -> list[Any]:
    return value if isinstance(value, list) else []


# Langflow 컴포넌트 클래스: LLM 초안을 결정론적으로 검증한 Workflow Skill 페이로드로 변환합니다.
class WorkflowSkillSavingResultNormalizer(Component):
    display_name = "04 Workflow Skill 등록 결과 정규화기"
    description = "LLM 후보를 08 Workflow Orchestrator 실행 계약에 맞춰 정규화하고 잘못된 단계·Tool·handoff를 차단합니다."
    inputs = [
        DataInput(name="payload", display_name="페이로드", required=True),
        MessageTextInput(name="llm_response", display_name="LLM 응답", required=True),
    ]
    outputs = [Output(name="payload_out", display_name="페이로드 출력", method="build_payload", types=["Data"])]

    # Langflow 출력 함수: 현재 요청과 LLM 응답을 정규화한 Data를 반환합니다.
    def build_payload(self) -> Data:
        return Data(data=normalize_authoring(getattr(self, "payload", None), getattr(self, "llm_response", "")))

# -*- coding: utf-8 -*-
# =============================================================================
# 컴포넌트 개요: 07 Workflow Skill 검수/저장 처리기
# 역할: 후보 스키마와 중복 정책을 재검증한 뒤 dry-run 계획 또는 MongoDB 저장을 수행합니다.
# 주요 입력: 페이로드, MongoDB URI·데이터베이스·컬렉션
# 주요 출력: 페이로드 출력(payload_out)
# 처리 흐름: 상위 오류 확인 -> 저장 스키마 검증 -> 유사 대상 확정 -> dry-run 또는 단건 MongoDB write
# 유지보수 포인트: replace는 유사 1건이면 canonical 문서를 교체하고, 없으면 신규 저장하며, 복수이면 반드시 차단합니다.
# =============================================================================

from __future__ import annotations

import json
import re
from copy import deepcopy
from datetime import datetime, timezone
from importlib import import_module
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, MessageTextInput, Output
from lfx.schema.data import Data

SECTION = "workflow_skills"
DEFAULT_DATABASE = "datagov"
DEFAULT_COLLECTION = "agent_v4_workflow_skills"
ALLOWED_ACTIONS = {"skip", "merge", "replace", "create_new"}
ALLOWED_TOOLS = {
    "run_data_analysis",
    "run_metadata_qa",
    "run_visualization",
    "save_domain_metadata",
    "save_table_catalog_metadata",
    "save_main_flow_filter_metadata",
}
MAX_STEP_QUESTION_CHARS = 4000
MAX_WORKFLOW_PAYLOAD_BYTES = 32768
WORKFLOW_KEY_PATTERN = re.compile(r"^[a-z][a-z0-9_-]{2,63}$")
STEP_ID_PATTERN = re.compile(r"^[A-Za-z][A-Za-z0-9_-]{0,63}$")
SECRET_PATTERNS = ("password", "passwd", "token", "secret", "api_key", "apikey", "authorization", "credential", "access_key", "private_key", "cookie")


# 주요 함수: 상위 검증과 duplicate 정책을 적용해 dry-run 또는 실제 MongoDB 저장 결과를 만듭니다.
def review_and_write(
    payload_value: Any,
    review_response: Any = "",
    mongo_uri: str = "",
    mongo_database: str = "",
    collection_name: str = "",
) -> dict[str, Any]:
    del review_response
    payload = _payload(payload_value)
    action = _duplicate_action(payload)
    dry_run = bool(_dict(payload.get("request")).get("dry_run", True))
    review = _deterministic_review(payload, action)
    payload["review"] = review
    if not review["ready_to_save"]:
        needs_input = bool(review["supplement_requests"])
        payload["write_result"] = {
            "success": False,
            "ready_to_save": False,
            "status": "needs_input" if needs_input else "error",
            "dry_run": dry_run,
            "saved_count": 0,
            "would_save_count": 0,
            "skipped_count": 0,
            "operation_by_key": [],
            "message": "추가 정보가 필요해 저장하지 않았습니다." if needs_input else "Workflow Skill 검증을 통과하지 못해 저장하지 않았습니다.",
            "errors": deepcopy(review["errors"]),
            "supplement_requests": deepcopy(review["supplement_requests"]),
        }
    elif dry_run:
        payload["write_result"] = _dry_run_result(payload, action)
    else:
        payload["write_result"] = _write_to_mongodb(payload, action, mongo_uri, mongo_database, collection_name)
    return payload


# 함수 설명: `_deterministic_review()`는 상위 오류·필수 스키마·비밀 필드·중복 조회 상태를 저장 차단 조건으로 검사합니다.
def _deterministic_review(payload: dict[str, Any], action: str) -> dict[str, Any]:
    refinement = deepcopy(_dict(payload.get("refinement")))
    errors = _unique_errors(_list(payload.get("errors")))
    missing = [str(item).strip() for item in _list(refinement.get("missing_information")) if str(item or "").strip()]
    if bool(refinement.get("needs_more_input")) and not missing:
        missing.append("Workflow 실행 순서를 확정할 수 있도록 원문을 보완해 주세요.")
    items = [_dict(item) for item in _list(payload.get("items")) if isinstance(item, dict)]
    if len(items) != 1:
        errors.append({"type": "workflow_item_count_error", "message": "한 번에 Workflow Skill 한 건만 저장할 수 있습니다."})
    for item in items:
        errors.extend(_validate_item(item))
        for path in _secret_paths(item):
            errors.append({"type": "credential_field_forbidden", "message": f"credential/secret 필드는 저장할 수 없습니다: {path}", "field": path, "key": item.get("key", "")})
    lookup = _dict(_dict(payload.get("trace")).get("duplicate_lookup"))
    if action != "create_new" and lookup.get("status") in {"error", "skipped"} and int(lookup.get("combined_count") or 0) == 0:
        errors.append(
            {
                "type": "identity_lookup_unavailable",
                "message": "기존 Workflow Skill 조회를 완료하지 못해 중복 여부를 확정할 수 없습니다.",
                "lookup_errors": deepcopy(_list(lookup.get("errors"))),
            }
        )
    resolution = _match_resolution(payload)
    if resolution["status"] == "ambiguous" and action != "create_new":
        errors.append(
            {
                "type": "ambiguous_replace_target" if action == "replace" else "ambiguous_identity_target",
                "message": "유사한 기존 Workflow Skill이 여러 건이라 저장 대상을 하나로 확정할 수 없습니다.",
                "existing_candidate_keys": deepcopy(resolution.get("candidate_keys", [])),
            }
        )
    errors = _unique_errors(errors)
    ready = len(items) == 1 and not errors and not missing
    return {
        "ready_to_save": ready,
        "item_reviews": [{"key": str(item.get("key") or ""), "ready_to_save": ready, "warnings": [], "errors": deepcopy(errors)} for item in items],
        "errors": errors,
        "supplement_requests": missing,
        "assumptions": [str(item).strip() for item in _list(refinement.get("assumptions")) if str(item or "").strip()],
        "refinement": refinement,
    }


# 함수 설명: `_validate_item()`은 Writer 경계에서 Workflow Skill 핵심 스키마를 한 번 더 검사합니다.
def _validate_item(item: dict[str, Any]) -> list[dict[str, Any]]:
    errors = []
    key = str(item.get("key") or "")
    payload = _dict(item.get("payload"))
    steps = [_dict(step) for step in _list(payload.get("steps"))]
    if item.get("section") != SECTION:
        errors.append({"type": "invalid_section", "message": f"section은 {SECTION}이어야 합니다.", "key": key})
    if not WORKFLOW_KEY_PATTERN.fullmatch(key):
        errors.append({"type": "invalid_workflow_key", "message": "유효한 workflow key가 없습니다.", "key": key})
    if not str(payload.get("display_name") or "").strip() or not str(payload.get("description") or "").strip():
        errors.append({"type": "missing_workflow_description", "message": "display_name과 description이 모두 필요합니다.", "key": key})
    if not 1 <= len(steps) <= 4:
        errors.append({"type": "invalid_step_count", "message": "실행 단계는 1~4개여야 합니다.", "key": key})
    seen = set()
    by_id = {}
    for index, step in enumerate(steps):
        step_id = str(step.get("step_id") or "")
        tool_name = str(step.get("tool_name") or "")
        dependencies = [str(value) for value in _list(step.get("depends_on"))]
        if not STEP_ID_PATTERN.fullmatch(step_id) or step_id in seen:
            errors.append({"type": "invalid_or_duplicate_step_id", "message": "step_id 형식이 잘못되었거나 중복되었습니다.", "key": key, "step_id": step_id})
        if tool_name not in ALLOWED_TOOLS:
            errors.append({"type": "unsupported_tool", "message": f"지원하지 않는 Tool입니다: {tool_name}", "key": key, "step_id": step_id})
        question = str(step.get("question") or "").strip()
        if not question:
            errors.append({"type": "missing_step_question", "message": "단계 question이 비어 있습니다.", "key": key, "step_id": step_id})
        elif len(question) > MAX_STEP_QUESTION_CHARS:
            errors.append({"type": "step_question_too_long", "message": f"단계 question은 {MAX_STEP_QUESTION_CHARS}자를 초과할 수 없습니다.", "key": key, "step_id": step_id})
        if any(dependency not in seen for dependency in dependencies):
            errors.append({"type": "dependency_not_prior", "message": "depends_on은 앞에서 정의된 step_id만 사용할 수 있습니다.", "key": key, "step_id": step_id})
        handoff = str(step.get("handoff") or "")
        if handoff not in {"none", "result_ref"}:
            errors.append({"type": "invalid_handoff", "message": "handoff는 none 또는 result_ref여야 합니다.", "key": key, "step_id": step_id})
        if handoff == "result_ref":
            source_tool = str(_dict(by_id.get(dependencies[0] if len(dependencies) == 1 else "")).get("tool_name") or "")
            if (
                len(dependencies) != 1
                or source_tool != "run_data_analysis"
                or tool_name not in {"run_data_analysis", "run_visualization"}
            ):
                errors.append({"type": "invalid_result_ref_contract", "message": "result_ref는 단일 run_data_analysis 결과를 다음 run_data_analysis 또는 run_visualization에 전달할 때만 사용할 수 있습니다.", "key": key, "step_id": step_id})
        if str(step.get("on_error") or "") not in {"stop", "continue"}:
            errors.append({"type": "invalid_on_error", "message": "on_error는 stop 또는 continue여야 합니다.", "key": key, "step_id": step_id})
        if index == 0 and (dependencies or handoff != "none"):
            errors.append({"type": "invalid_first_step", "message": "첫 단계에는 dependency나 result_ref handoff를 지정할 수 없습니다.", "key": key, "step_id": step_id})
        seen.add(step_id)
        by_id[step_id] = step
    payload_bytes = len(json.dumps(payload, ensure_ascii=False, separators=(",", ":")).encode("utf-8"))
    if payload_bytes > MAX_WORKFLOW_PAYLOAD_BYTES:
        errors.append({"type": "workflow_payload_too_large", "message": f"Workflow Skill payload는 UTF-8 {MAX_WORKFLOW_PAYLOAD_BYTES}바이트를 초과할 수 없습니다.", "key": key, "payload_bytes": payload_bytes})
    return errors


# 함수 설명: `_dry_run_result()`는 중복 정책에 따라 실제 저장 시 수행될 한 건의 operation을 계산합니다.
def _dry_run_result(payload: dict[str, Any], action: str) -> dict[str, Any]:
    item = _dict(_list(payload.get("items"))[0])
    requested_key = str(item.get("key") or "")
    resolution = _match_resolution(payload)
    existing = _dict(resolution.get("existing_item"))
    target_key = str(existing.get("key") or requested_key) if existing and action != "create_new" else requested_key
    operation = _operation(action, bool(existing))
    record = _operation_record(requested_key, target_key, operation, existing, str(resolution.get("match_type") or ""))
    would_save = 0 if operation == "skipped" else 1
    return {
        "success": True,
        "ready_to_save": True,
        "status": "dry_run",
        "dry_run": True,
        "saved_count": 0,
        "would_save_count": would_save,
        "skipped_count": 1 - would_save,
        "operation_by_key": [record],
        "message": "드라이런입니다. MongoDB에는 저장하지 않았습니다.",
        "keys": [target_key],
        "errors": [],
    }


# 함수 설명: `_write_to_mongodb()`는 preflight로 canonical 대상을 재확인한 뒤 단건 Workflow 문서를 저장합니다.
def _write_to_mongodb(payload: dict[str, Any], action: str, mongo_uri: str, mongo_database: str, collection_name: str) -> dict[str, Any]:
    uri = str(mongo_uri or "").strip()
    database = str(mongo_database or DEFAULT_DATABASE).strip() or DEFAULT_DATABASE
    collection_name = str(collection_name or DEFAULT_COLLECTION).strip() or DEFAULT_COLLECTION
    if not uri:
        return {"success": False, "ready_to_save": False, "status": "error", "saved_count": 0, "message": "MongoDB 연결 URI가 없어 저장하지 않았습니다.", "errors": [{"type": "missing_mongo_config", "message": "mongo_uri가 필요합니다."}]}
    client = None
    try:
        client = getattr(import_module("pymongo"), "MongoClient")(uri, serverSelectionTimeoutMS=5000)
        collection = client[database][collection_name]
        item = deepcopy(_dict(_list(payload.get("items"))[0]))
        requested_key = str(item.get("key") or "")
        resolution = _match_resolution(payload)
        if resolution["status"] == "ambiguous" and action != "create_new":
            return _write_error("ambiguous_replace_target", "유사 대상이 여러 건이라 저장하지 않았습니다.", database, collection_name, resolution.get("candidate_keys", []))
        existing = _dict(resolution.get("existing_item"))
        if existing and action != "create_new":
            target_key = str(existing.get("key") or requested_key)
            target_id = str(existing.get("_id") or f"workflow:{target_key}")
            current = _dict(collection.find_one({"_id": target_id}))
            if not current:
                return _write_error("target_disappeared", "유사 대상으로 확정한 기존 Workflow Skill이 저장 직전에 사라졌습니다.", database, collection_name, [target_key])
            existing = current
        else:
            exact = _dict(collection.find_one({"_id": f"workflow:{requested_key}"}))
            existing = exact if exact and action != "create_new" else {}
            target_key = str(existing.get("key") or requested_key)
            target_id = str(existing.get("_id") or f"workflow:{target_key}")
        if action == "create_new":
            target_key = _next_key(collection, requested_key)
            target_id = f"workflow:{target_key}"
            existing = {}
        operation = _operation(action, bool(existing))
        if operation == "skipped":
            record = _operation_record(requested_key, target_key, operation, existing, str(resolution.get("match_type") or ""))
            return {"success": True, "ready_to_save": True, "status": "skipped", "saved_count": 0, "skipped_count": 1, "operation_by_key": [record], "database": database, "collection_name": collection_name, "message": "유사한 기존 Workflow Skill을 유지했습니다.", "errors": []}
        if operation == "merged":
            document = _deep_merge(existing, item)
        else:
            document = deepcopy(item)
        document = {
            "_id": target_id,
            "section": SECTION,
            "key": target_key,
            "status": str(document.get("status") or "active"),
            "payload": deepcopy(_dict(document.get("payload"))),
            "updated_at": datetime.now(timezone.utc).isoformat(),
            "registration_trace": {"raw_text": _redact_raw_text(str(_dict(payload.get("request")).get("raw_text") or ""))},
        }
        write_result = collection.replace_one({"_id": target_id}, document, upsert=not bool(existing))
        if existing and getattr(write_result, "matched_count", 1) != 1:
            raise RuntimeError(f"target document was not matched: {target_id}")
        record = _operation_record(requested_key, target_key, operation, existing, str(resolution.get("match_type") or ""))
        return {"success": True, "ready_to_save": True, "status": "saved", "saved_count": 1, "skipped_count": 0, "operation_by_key": [record], "database": database, "collection_name": collection_name, "message": "Workflow Skill 저장을 완료했습니다.", "errors": []}
    except Exception as exc:
        return {"success": False, "ready_to_save": False, "status": "error", "saved_count": 0, "database": database, "collection_name": collection_name, "message": "MongoDB 저장 중 오류가 발생했습니다.", "errors": [{"type": "mongo_write_error", "message": str(exc)}]}
    finally:
        if client is not None:
            client.close()


# 함수 설명: `_match_resolution()`은 similarity 결과를 저장 가능한 유일 대상·미일치·모호함 중 하나로 확정합니다.
def _match_resolution(payload: dict[str, Any]) -> dict[str, Any]:
    matches = [_dict(match) for match in _list(payload.get("existing_matches"))]
    if any(match.get("identity_resolution") == "ambiguous" for match in matches):
        candidates = []
        for match in matches:
            candidates.extend(_list(match.get("existing_candidate_keys")))
        return {"status": "ambiguous", "candidate_keys": list(dict.fromkeys(str(value) for value in candidates if str(value).strip()))}
    resolved = [match for match in matches if isinstance(match.get("existing_item"), dict)]
    if len(resolved) > 1:
        return {"status": "ambiguous", "candidate_keys": [str(match.get("existing_key") or "") for match in resolved]}
    if not resolved:
        return {"status": "not_found", "candidate_keys": []}
    match = resolved[0]
    return {"status": "unique", "existing_item": deepcopy(_dict(match.get("existing_item"))), "match_type": str(match.get("match_type") or "")}


# 함수 설명: `_operation()`은 중복 action과 기존 문서 존재 여부를 실제 저장 operation 이름으로 변환합니다.
def _operation(action: str, has_existing: bool) -> str:
    if action == "create_new":
        return "created_new"
    if has_existing and action == "skip":
        return "skipped"
    if has_existing and action == "merge":
        return "merged"
    if has_existing and action == "replace":
        return "replaced"
    return "inserted"


# 함수 설명: `_operation_record()`는 요청 key와 실제 canonical target을 저장 결과에 함께 기록합니다.
def _operation_record(requested_key: str, target_key: str, operation: str, existing: dict[str, Any], match_type: str) -> dict[str, Any]:
    record = {"key": target_key, "operation": operation, "target_key": target_key, "target_id": str(existing.get("_id") or f"workflow:{target_key}")}
    if requested_key != target_key:
        record["requested_key"] = requested_key
    if match_type:
        record["match_type"] = match_type
    return record


# 함수 설명: `_next_key()`는 create_new 정책에서 충돌하지 않는 `_copy` suffix key를 계산합니다.
def _next_key(collection: Any, key: str) -> str:
    if not collection.find_one({"_id": f"workflow:{key}"}):
        return key
    base = f"{key}_copy"
    candidate = base
    index = 2
    while collection.find_one({"_id": f"workflow:{candidate}"}):
        candidate = f"{base}_{index}"
        index += 1
    return candidate


# 함수 설명: `_deep_merge()`는 새 Workflow 필드만 기존 문서에 재귀 병합하고 내부 ID는 유지합니다.
def _deep_merge(existing: dict[str, Any], incoming: dict[str, Any]) -> dict[str, Any]:
    merged = deepcopy(existing)
    for key, value in incoming.items():
        if key in {"_id", "updated_at", "registration_trace"}:
            continue
        if isinstance(value, dict) and isinstance(merged.get(key), dict):
            merged[key] = _deep_merge(merged[key], value)
        elif isinstance(value, list) and isinstance(merged.get(key), list):
            combined = deepcopy(merged[key])
            for item in value:
                if item not in combined:
                    combined.append(deepcopy(item))
            merged[key] = combined
        else:
            merged[key] = deepcopy(value)
    return merged


# 함수 설명: `_write_error()`는 preflight 저장 차단 오류를 공통 write_result 계약으로 만듭니다.
def _write_error(error_type: str, message: str, database: str, collection: str, candidate_keys: Any) -> dict[str, Any]:
    return {"success": False, "ready_to_save": False, "status": "error", "saved_count": 0, "database": database, "collection_name": collection, "message": message, "errors": [{"type": error_type, "message": message, "existing_candidate_keys": deepcopy(_list(candidate_keys))}]}


# 함수 설명: `_secret_paths()`는 Workflow 후보 전체에서 credential로 의심되는 field 경로를 재귀 탐색합니다.
def _secret_paths(value: Any, prefix: str = "") -> list[str]:
    paths = []
    if isinstance(value, dict):
        for key, item in value.items():
            path = f"{prefix}.{key}" if prefix else str(key)
            normalized = re.sub(r"[^a-z0-9]+", "_", str(key).lower())
            if any(pattern in normalized for pattern in SECRET_PATTERNS):
                paths.append(path)
            else:
                paths.extend(_secret_paths(item, path))
    elif isinstance(value, list):
        for index, item in enumerate(value):
            paths.extend(_secret_paths(item, f"{prefix}[{index}]"))
    return paths


# 함수 설명: `_redact_raw_text()`는 등록 원문에 포함될 수 있는 credential 값을 trace에 남기기 전에 마스킹합니다.
def _redact_raw_text(value: str, limit: int = 2000) -> str:
    pattern = re.compile(r"(?i)(password|passwd|token|secret|api[_-]?key|authorization|credential)([\"']?\s*[:=]\s*[\"']?)([^\s,;\"'}]+)")
    return pattern.sub(r"\1\2***", str(value or ""))[:limit]


# 함수 설명: `_duplicate_action()`은 요청에 지정된 중복 정책을 허용 목록으로 제한합니다.
def _duplicate_action(payload: dict[str, Any]) -> str:
    action = str(_dict(payload.get("request")).get("duplicate_action") or "skip").strip().lower()
    return action if action in ALLOWED_ACTIONS else "skip"


# 함수 설명: `_unique_errors()`는 동일한 오류를 발생 순서대로 한 건씩만 유지합니다.
def _unique_errors(values: list[Any]) -> list[dict[str, Any]]:
    result = []
    seen = set()
    for value in values:
        item = value if isinstance(value, dict) else {"type": "review_error", "message": str(value)}
        marker = (item.get("type"), item.get("key"), item.get("step_id"), item.get("field"), item.get("message"))
        if marker not in seen:
            seen.add(marker)
            result.append(deepcopy(item))
    return result


# 함수 설명: `_payload()`는 Langflow Data 또는 dict에서 변경에 안전한 복사본을 꺼냅니다.
def _payload(value: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    return deepcopy(data) if isinstance(data, dict) else {}


# 함수 설명: `_dict()`는 값이 dict일 때만 반환하고 아니면 빈 dict를 사용합니다.
def _dict(value: Any) -> dict[str, Any]:
    return value if isinstance(value, dict) else {}


# 함수 설명: `_list()`는 값이 list일 때만 반환하고 아니면 빈 목록을 사용합니다.
def _list(value: Any) -> list[Any]:
    return value if isinstance(value, list) else []


# Langflow 컴포넌트 클래스: 결정론적 검수와 standalone MongoDB 저장을 하나의 Writer 포트로 제공합니다.
class WorkflowSkillReviewWriter(Component):
    display_name = "07 Workflow Skill 검수/저장 처리기"
    description = "Workflow 계약과 유사 대상을 재검증한 뒤 dry-run 또는 MongoDB 저장을 수행합니다."
    inputs = [
        DataInput(name="payload", display_name="페이로드", required=True),
        MessageTextInput(name="mongo_uri", display_name="MongoDB 연결 URI", required=False, value=""),
        MessageTextInput(name="mongo_database", display_name="MongoDB 데이터베이스", required=False, value=DEFAULT_DATABASE),
        MessageTextInput(name="collection_name", display_name="컬렉션 이름", required=False, value=DEFAULT_COLLECTION),
    ]
    outputs = [Output(name="payload_out", display_name="페이로드 출력", method="build_payload", types=["Data"])]

    # Langflow 출력 함수: 현재 검수 결과와 저장 결과가 포함된 페이로드를 반환합니다.
    def build_payload(self) -> Data:
        return Data(
            data=review_and_write(
                getattr(self, "payload", None),
                "",
                getattr(self, "mongo_uri", ""),
                getattr(self, "mongo_database", DEFAULT_DATABASE),
                getattr(self, "collection_name", DEFAULT_COLLECTION),
            )
        )

# -*- coding: utf-8 -*-
# =============================================================================
# 컴포넌트 개요: 08 Workflow Skill 등록 응답 정규화기
# 역할: 검수·저장 결과를 채팅과 API가 함께 사용하는 간결한 구조화 응답으로 정리합니다.
# 주요 입력: 페이로드(payload)
# 주요 출력: 페이로드 출력(payload_out)
# 처리 흐름: 저장 상태 판정 -> Workflow·단계 요약 -> 안내·다음 단계 -> compact write result 구성
# 유지보수 포인트: 전체 MongoDB 문서나 내부 중복 조회 payload를 응답에 복제하지 않습니다.
# =============================================================================

from __future__ import annotations

from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, Output
from lfx.schema.data import Data


# 주요 함수: 내부 Workflow Skill 저장 페이로드를 사용자 응답용 compact 계약으로 변환합니다.
def build_response(payload_value: Any) -> dict[str, Any]:
    payload = _payload(payload_value)
    write_result = _dict(payload.get("write_result"))
    review = _dict(payload.get("review"))
    items = [_dict(item) for item in _list(payload.get("items")) if isinstance(item, dict)]
    status = _status(write_result, review)
    rows = [_row(item, write_result) for item in items]
    message = _headline(status, write_result)
    return {
        "metadata_type": "workflow_skill",
        "metadata_label": "Workflow Skill",
        "status": status,
        "success": status in {"dry_run", "saved", "skipped"},
        "message": message,
        "answer_message": message,
        "answer_sections": {
            "summary": {"headline": message},
            "key_points": _key_points(items, write_result),
            "target_table": {
                "title": "등록 대상 Workflow Skill",
                "columns": ["Workflow Key", "표시 이름", "단계 수", "실행 Tool", "처리"],
                "rows": rows,
                "display_limit": 5,
            },
            "workflow_steps": _step_sections(items),
            "notices": _notices(review, write_result, payload),
            "next_steps": _next_steps(status),
        },
        "data": {"columns": ["Workflow Key", "표시 이름", "단계 수", "실행 Tool", "처리"], "rows": rows, "row_count": len(rows)},
        "metadata_authoring": {
            "requested_action": str(_dict(payload.get("request")).get("duplicate_action") or "skip"),
            "dry_run": bool(write_result.get("dry_run", _dict(payload.get("request")).get("dry_run", True))),
            "keys": [str(item.get("key") or "") for item in items],
            "workflow_steps": _step_sections(items),
        },
        "write_result": _compact_write_result(write_result),
        "trace": {"workflow_contract": deepcopy(_dict(_dict(payload.get("trace")).get("workflow_contract")))},
    }


# 함수 설명: `_status()`는 Writer 결과와 review 상태를 외부 응답의 고정 상태로 변환합니다.
def _status(write_result: dict[str, Any], review: dict[str, Any]) -> str:
    if write_result.get("dry_run") and write_result.get("success"):
        return "dry_run"
    status = str(write_result.get("status") or "")
    if status in {"saved", "skipped", "needs_input", "error", "partial_success"}:
        return status
    if _list(review.get("supplement_requests")):
        return "needs_input"
    return "error" if write_result.get("success") is False else "unknown"


# 함수 설명: `_headline()`은 상태별 등록 결과를 한 문장으로 요약합니다.
def _headline(status: str, write_result: dict[str, Any]) -> str:
    if status == "dry_run":
        return f"Workflow Skill {int(write_result.get('would_save_count') or 0)}건의 저장 계획을 확인했습니다."
    if status == "saved":
        return f"Workflow Skill {int(write_result.get('saved_count') or 0)}건을 저장했습니다."
    if status == "skipped":
        return "유사한 기존 Workflow Skill을 유지하고 저장을 건너뛰었습니다."
    if status == "needs_input":
        return "Workflow Skill을 확정하려면 입력 정보를 보완해야 합니다."
    if status == "partial_success":
        return "Workflow Skill 저장이 일부만 완료되었습니다."
    return str(write_result.get("message") or "Workflow Skill 저장을 완료하지 못했습니다.")


# 함수 설명: `_row()`는 Workflow 후보와 operation을 사용자 표의 한 행으로 변환합니다.
def _row(item: dict[str, Any], write_result: dict[str, Any]) -> dict[str, Any]:
    payload = _dict(item.get("payload"))
    steps = [_dict(step) for step in _list(payload.get("steps"))]
    operation = _operation_for_key(str(item.get("key") or ""), write_result)
    return {
        "Workflow Key": str(item.get("key") or ""),
        "표시 이름": str(payload.get("display_name") or ""),
        "단계 수": len(steps),
        "실행 Tool": " → ".join(str(step.get("tool_name") or "") for step in steps),
        "처리": _operation_label(operation, bool(write_result.get("dry_run"))),
    }


# 함수 설명: `_step_sections()`는 각 단계의 질문·의존성·handoff를 JSON 대신 읽기 쉬운 요약 목록으로 만듭니다.
def _step_sections(items: list[dict[str, Any]]) -> list[dict[str, Any]]:
    result = []
    for item in items:
        payload = _dict(item.get("payload"))
        for index, step in enumerate(_list(payload.get("steps")), start=1):
            step = _dict(step)
            dependencies = ", ".join(str(value) for value in _list(step.get("depends_on"))) or "없음"
            result.append(
                {
                    "순서": index,
                    "단계": str(step.get("step_id") or ""),
                    "Tool": str(step.get("tool_name") or ""),
                    "질문": str(step.get("question") or ""),
                    "선행 단계": dependencies,
                    "결과 전달": "앞 단계 실제 결과 사용" if step.get("handoff") == "result_ref" else "순서만 보장",
                    "오류 정책": "중단" if step.get("on_error") == "stop" else "다음 단계 계속",
                }
            )
    return result


# 함수 설명: `_key_points()`는 생성 후보와 저장 결과에서 한눈에 볼 핵심 건수를 계산합니다.
def _key_points(items: list[dict[str, Any]], write_result: dict[str, Any]) -> list[str]:
    step_count = sum(len(_list(_dict(item.get("payload")).get("steps"))) for item in items)
    return [
        f"생성된 Workflow Skill 후보는 {len(items)}건입니다.",
        f"순차 실행 단계는 총 {step_count}개입니다.",
        f"저장 처리 결과: {_operation_summary(write_result) or str(write_result.get('message') or '처리 결과 없음')}",
    ]


# 함수 설명: `_notices()`는 오류·보완 요청·가정을 중복 없는 사용자 안내 목록으로 정리합니다.
def _notices(review: dict[str, Any], write_result: dict[str, Any], payload: dict[str, Any]) -> list[dict[str, str]]:
    notices = []
    for error in _list(write_result.get("errors")) + _list(review.get("errors")):
        message = str(_dict(error).get("message") or error).strip()
        if message and message not in {item["message"] for item in notices}:
            notices.append({"type": "error", "title": "오류", "message": message})
    for message in _list(review.get("supplement_requests")):
        text = str(message).strip()
        if text:
            notices.append({"type": "supplement", "title": "추가 확인 필요", "message": text})
    for message in _list(review.get("assumptions")):
        text = str(message).strip()
        if text:
            notices.append({"type": "info", "title": "적용 가정", "message": text})
    if payload.get("conflict_warnings"):
        notices.append({"type": "warning", "title": "유사 항목", "message": f"기존 Workflow Skill과 겹치는 후보 {len(_list(payload.get('conflict_warnings')))}건을 확인했습니다."})
    return notices[:12]


# 함수 설명: `_next_steps()`는 dry-run·저장·오류 상태에 맞는 다음 작업을 안내합니다.
def _next_steps(status: str) -> list[str]:
    if status == "dry_run":
        return ["저장 계획과 단계 순서가 맞으면 Dry Run을 false로 바꿔 다시 실행하세요.", "저장 후 08 Workflow Orchestrator에서 intent example 또는 workflow key로 호출해 보세요."]
    if status == "saved":
        return ["08 Workflow Orchestrator의 다음 실행에서 등록한 Workflow Skill을 호출해 보세요.", "잘못 선택되면 keywords와 excluded_keywords를 조정하세요."]
    if status == "needs_input":
        return ["확인할 점의 누락 정보를 원문에 추가해 다시 실행하세요."]
    return ["오류 메시지와 MongoDB standalone 입력값을 확인한 뒤 다시 실행하세요."]


# 함수 설명: `_operation_for_key()`는 현재 Workflow 후보에 대응하는 Writer operation을 찾습니다.
def _operation_for_key(key: str, write_result: dict[str, Any]) -> str:
    operations = [_dict(item) for item in _list(write_result.get("operation_by_key"))]
    for operation in operations:
        if key in {str(operation.get("key") or ""), str(operation.get("requested_key") or "")}:
            return str(operation.get("operation") or "")
    return str(operations[0].get("operation") or "") if len(operations) == 1 else ""


# 함수 설명: `_operation_label()`은 내부 operation 이름을 자연어 처리 상태로 변환합니다.
def _operation_label(operation: str, dry_run: bool) -> str:
    labels = {"inserted": "신규 저장", "replaced": "기존 Skill 교체", "merged": "기존 Skill 병합", "skipped": "기존 Skill 유지", "created_new": "새 Key로 저장"}
    label = labels.get(operation, "처리 안 함" if not operation else operation)
    return f"{label} 예정" if dry_run and operation != "skipped" else label


# 함수 설명: `_operation_summary()`는 Writer operation별 건수를 한 문장으로 요약합니다.
def _operation_summary(write_result: dict[str, Any]) -> str:
    counts = {}
    for item in _list(write_result.get("operation_by_key")):
        operation = str(_dict(item).get("operation") or "")
        if operation:
            label = _operation_label(operation, bool(write_result.get("dry_run")))
            counts[label] = counts.get(label, 0) + 1
    return ", ".join(f"{label} {count}건" for label, count in counts.items())


# 함수 설명: `_compact_write_result()`는 외부 응답에 필요한 저장 상태·operation·오류만 남깁니다.
def _compact_write_result(write_result: dict[str, Any]) -> dict[str, Any]:
    allowed = {"success", "ready_to_save", "status", "dry_run", "saved_count", "would_save_count", "skipped_count", "operation_by_key", "database", "collection_name", "message", "errors", "keys"}
    return {key: deepcopy(value) for key, value in write_result.items() if key in allowed}


# 함수 설명: `_payload()`는 Langflow Data 또는 dict에서 변경에 안전한 복사본을 꺼냅니다.
def _payload(value: Any) -> dict[str, Any]:
    data = getattr(value, "data", value)
    return deepcopy(data) if isinstance(data, dict) else {}


# 함수 설명: `_dict()`는 값이 dict일 때만 반환하고 아니면 빈 dict를 사용합니다.
def _dict(value: Any) -> dict[str, Any]:
    return value if isinstance(value, dict) else {}


# 함수 설명: `_list()`는 값이 list일 때만 반환하고 아니면 빈 목록을 사용합니다.
def _list(value: Any) -> list[Any]:
    return value if isinstance(value, list) else []


# Langflow 컴포넌트 클래스: Writer 결과를 단일 구조화 응답 포트로 제공합니다.
class WorkflowSkillSavingResponseBuilder(Component):
    display_name = "08 Workflow Skill 등록 응답 정규화기"
    description = "Workflow Skill 검수·저장 결과를 채팅과 API가 공유할 compact 응답으로 변환합니다."
