PLOT_TOP = 54
PLOT_BOTTOM = 470
COLORS = ("#2563eb", "#dc2626", "#059669")
DATE_FORMATS = ("%Y%m%d", "%Y-%m-%d", "%Y/%m/%d", "%Y-%m-%d %H:%M:%S", "%Y-%m-%dT%H:%M:%S")
DATE_COLUMN_TOKENS = ("DATE", "_DT", "DT_", "WORK_DT", "BASE_DT", "일자", "날짜", "시간")
METRIC_COLUMN_TOKENS = (
    "PRODUCTION",
    "WIP",
    "QTY",
    "COUNT",
    "CNT",
    "UPH",
    "RATE",
    "RATIO",
    "AMOUNT",
    "생산",
    "재공",
    "수량",
    "실적",
    "계획",
    "달성률",
    "비율",
    "건수",
)


# 함수 설명: 임의 값을 앞뒤 공백이 제거된 문자열로 안전하게 바꿉니다.
def _text(value: Any) -> str:
    return "" if value is None else str(value).strip()


# 함수 설명: 사용자·오류 문자열이 계약 상한을 넘지 않도록 말줄임 처리합니다.
def _clip(value: Any, limit: int) -> str:
    text = _text(value)
    return text if len(text) <= limit else text[: max(0, limit - 1)].rstrip() + "…"


# 함수 설명: 시각화 오류와 경고를 공통 type/message 구조로 만듭니다.
def _issue(issue_type: str, message: Any) -> dict[str, str]:
    return {"type": _clip(issue_type, 100), "message": _clip(message, MAX_ERROR_CHARS)}


# 함수 설명: Langflow Message 또는 일반 값에서 질문과 세션 ID를 추출합니다.
def _message_parts(value: Any) -> tuple[str, str]:
    data = getattr(value, "data", None)
    data = data if isinstance(data, dict) else {}
    question = _text(getattr(value, "text", None) or data.get("text") or value)
    session_id = _text(getattr(value, "session_id", None) or data.get("session_id"))
    return _clip(question, MAX_QUESTION_CHARS), session_id


# 함수 설명: 문자열 또는 data_ref 객체에서 MongoDB 문서 식별자를 꺼냅니다.
def _ref_id(value: Any) -> str:
    if hasattr(value, "model_dump"):
        value = value.model_dump()
    if isinstance(value, dict):
        value = value.get("ref_id") or value.get("result_ref") or value.get("data_ref") or value.get("_id")
    return _text(value)


# 함수 설명: 화면 문자열 입력을 지정된 최소·최대 범위의 정수로 제한합니다.
def _bounded_int(value: Any, default: int, lower: int, upper: int) -> int:
    try:
        parsed = int(float(_text(value))) if _text(value) else default
    except (TypeError, ValueError, OverflowError):
        parsed = default
    return max(lower, min(parsed, upper))


# 함수 설명: 결과 행의 key 등장 순서를 유지하면서 전체 컬럼 목록을 만듭니다.
def _columns_from_rows(rows: list[dict[str, Any]]) -> list[str]:
    columns: list[str] = []
    for row in rows:
        for key in row:
            column = _text(key)
            if column and column not in columns:
                columns.append(column)
    return columns


# 함수 설명: 컬럼명이 일자·시간 축을 나타내는지 이름 규칙으로 판정합니다.
def _is_date_column(column: str) -> bool:
    normalized = column.upper().replace(" ", "_")
    return any(token in normalized for token in DATE_COLUMN_TOKENS)


# 함수 설명: bool·빈 값을 제외하고 차트에 사용할 수 있는 유한 실수로 변환합니다.
def _to_number(value: Any) -> float | None:
    if value is None or isinstance(value, bool):
        return None
    if isinstance(value, (int, float)):
        number = float(value)
        return number if isfinite(number) else None
    text = _text(value).replace(",", "")
    if text.endswith("%"):
        text = text[:-1].strip()
    if not re.fullmatch(r"[-+]?(?:\d+(?:\.\d*)?|\.\d+)", text):
        return None
    try:
        number = float(text)
    except (TypeError, ValueError, OverflowError):
        return None
    return number if isfinite(number) else None


# 함수 설명: 선택된 수량 지표의 NULL·빈 문자열은 데이터 분석 출력 계약과 맞춰 0으로 표시합니다.
def _chart_number(value: Any) -> float | None:
    if value is None or (isinstance(value, str) and not value.strip()):
        return 0.0
    return _to_number(value)


# 함수 설명: 각 컬럼의 비어 있지 않은 값 중 대부분이 숫자로 변환되는 컬럼만 수치 축 후보로 선택합니다.
def _numeric_columns(rows: list[dict[str, Any]], columns: list[str]) -> list[str]:
    numeric: list[str] = []
    for column in columns:
        if _is_date_column(column):
            continue
        nonempty = [row.get(column) for row in rows if row.get(column) not in (None, "")]
        if not nonempty:
            normalized = column.upper().replace(" ", "_")
            if any(token in normalized for token in METRIC_COLUMN_TOKENS):
                numeric.append(column)
            continue
        converted = sum(_to_number(value) is not None for value in nonempty)
        if converted > 0 and converted / len(nonempty) >= 0.8:
            numeric.append(column)
    return numeric


# 함수 설명: 질문 본문에 실제 컬럼명이 명시된 경우 원본 컬럼 순서대로 찾아냅니다.
def _explicit_columns(question: str, columns: list[str]) -> list[str]:
    folded = question.casefold()
    return [column for column in columns if column.casefold() in folded]


# 함수 설명: 질문과 제조 지표 명칭을 기준으로 수치 컬럼의 기본 우선순위를 계산합니다.
def _metric_score(column: str, question: str, index: int) -> tuple[int, int]:
    normalized = column.upper().replace(" ", "_")
    score = 100 if column.casefold() in question.casefold() else 0
    for rank, token in enumerate(METRIC_COLUMN_TOKENS):
        if token in normalized:
            score += len(METRIC_COLUMN_TOKENS) - rank
    if any(token in normalized for token in ("SEQ", "ID", "LEAD", "YEAR", "MONTH")):
        score -= 20
    return score, -index


# 주요 함수: 질문과 결과 스키마만으로 x축, 최대 세 개의 y축 지표, line/bar 유형을 결정합니다.
def select_chart_plan(rows: list[dict[str, Any]], question: str) -> tuple[dict[str, Any], dict[str, str] | None]:
    columns = _columns_from_rows(rows)
    if not columns:
        return {}, _issue("missing_columns", "시각화할 결과 컬럼이 없습니다.")
    numeric = _numeric_columns(rows, columns)
    explicit = _explicit_columns(question, columns)
    date_columns = [column for column in columns if _is_date_column(column)]
    categorical = [column for column in columns if column not in numeric]
    x_candidates = [column for column in explicit if column in date_columns or column in categorical]
    x_candidates.extend(column for column in date_columns if column not in x_candidates)
    x_candidates.extend(column for column in categorical if column not in x_candidates)
    if not x_candidates:
        x_candidates.extend(column for column in columns if column not in numeric)
    x_column = x_candidates[0] if x_candidates else columns[0]
    y_candidates = [column for column in explicit if column in numeric and column != x_column]
    remaining = [column for column in numeric if column != x_column and column not in y_candidates]
    remaining.sort(key=lambda column: _metric_score(column, question, columns.index(column)), reverse=True)
    if not y_candidates and remaining:
        y_candidates.append(remaining.pop(0))
    if any(token in question.casefold() for token in ("비교", "함께", "각각", "모두")):
        y_candidates.extend(remaining[: SERIES_LIMIT - len(y_candidates)])
    y_columns = y_candidates[:SERIES_LIMIT]
    if not y_columns:
        return {}, _issue("missing_numeric_metric", "시각화할 수치 컬럼을 결과에서 찾지 못했습니다.")
    lowered = question.casefold()
    if any(token in lowered for token in ("막대", "bar")):
        chart_type = "bar"
    elif any(token in lowered for token in ("선 그래프", "라인", "line")) or _is_date_column(x_column):
        chart_type = "line"
    else:
        chart_type = "bar"
    title = _clip(question.rstrip(" .?!"), 160) or "데이터 시각화"
    return {"title": title, "chart_type": chart_type, "x_column": x_column, "y_columns": y_columns, "columns": columns}, None


# 함수 설명: 일자 형태의 값을 정렬 가능한 datetime으로 변환하되 원본 표시값은 변경하지 않습니다.
def _temporal_key(value: Any) -> datetime | None:
    text = _text(value)
    if not text:
        return None
    for date_format in DATE_FORMATS:
        try:
            return datetime.strptime(text, date_format)
        except ValueError:
            continue
    try:
        return datetime.fromisoformat(text.replace("Z", "+00:00"))
    except (TypeError, ValueError):
        return None


# 함수 설명: 일자 x축인 경우 해석 가능한 값만 시간순으로 안정 정렬하고 그 외에는 조회 순서를 유지합니다.
def _ordered_rows(rows: list[dict[str, Any]], x_column: str) -> list[dict[str, Any]]:
    if not _is_date_column(x_column):
        return list(rows)
    parsed = [_temporal_key(row.get(x_column)) for row in rows]
    if sum(value is not None for value in parsed) < max(1, int(len(rows) * 0.8)):
        return list(rows)
    indexed = list(enumerate(rows))
    maximum = datetime.max
    indexed.sort(key=lambda item: (parsed[item[0]] or maximum, item[0]))
    return [row for _, row in indexed]


# 함수 설명: 행이 화면 상한을 넘으면 첫·끝을 포함한 균등 간격으로 점을 줄여 SVG 크기를 제한합니다.
def _sample_rows(rows: list[dict[str, Any]], limit: int) -> tuple[list[dict[str, Any]], bool]:
    if len(rows) <= limit:
        return list(rows), False
    if limit <= 1:
        return [rows[0]], True
    indexes = [round(index * (len(rows) - 1) / (limit - 1)) for index in range(limit)]
    return [rows[index] for index in indexes], True


# 함수 설명: 숫자를 불필요한 소수점 없이 축과 표에 표시합니다.
def _format_number(value: float) -> str:
    if abs(value - round(value)) < 1e-9:
        return f"{round(value):,}"
    return f"{value:,.4f}".rstrip("0").rstrip(".")


# 함수 설명: SVG 좌표 계산용 전체 수치 범위를 0 포함 형태로 만들고 동일값 범위를 보정합니다.
def _value_range(rows: list[dict[str, Any]], y_columns: list[str]) -> tuple[float, float]:
    values = [number for row in rows for column in y_columns if (number := _chart_number(row.get(column))) is not None]
    minimum = min([0.0, *values]) if values else 0.0
    maximum = max([0.0, *values]) if values else 1.0
    if abs(maximum - minimum) < 1e-12:
        maximum = minimum + 1.0
    return minimum, maximum


# 함수 설명: 실제 수치를 SVG plot 영역의 y 좌표로 변환합니다.
def _y_position(value: float, minimum: float, maximum: float) -> float:
    plot_height = PLOT_BOTTOM - PLOT_TOP
    return PLOT_BOTTOM - ((value - minimum) / (maximum - minimum)) * plot_height


# 함수 설명: 각 행의 x축 중심 좌표를 line 또는 grouped bar 배치에 맞게 계산합니다.
def _x_position(index: int, count: int) -> float:
    plot_width = PLOT_RIGHT - PLOT_LEFT
    return PLOT_LEFT + plot_width / 2 if count <= 1 else PLOT_LEFT + index * plot_width / (count - 1)


# 주요 함수: 외부 JavaScript 없이 선/막대 차트, 축, 범례, 접근성 title을 포함한 inline SVG를 생성합니다.
def render_svg_chart(rows: list[dict[str, Any]], plan: dict[str, Any]) -> str:
    x_column = str(plan["x_column"])
    y_columns = [str(column) for column in plan["y_columns"]]
    minimum, maximum = _value_range(rows, y_columns)
    parts = [
        f'<svg viewBox="0 0 {SVG_WIDTH} {SVG_HEIGHT}" role="img" aria-labelledby="chart-title chart-desc">',
        f'<title id="chart-title">{html.escape(str(plan["title"]))}</title>',
        f'<desc id="chart-desc">{html.escape(x_column)} 기준 {html.escape(", ".join(y_columns))} {plan["chart_type"]} 차트</desc>',
        '<rect width="100%" height="100%" rx="18" fill="#ffffff"/>',
    ]
    for tick in range(6):
        ratio = tick / 5
        value = maximum - (maximum - minimum) * ratio
        y = PLOT_TOP + (PLOT_BOTTOM - PLOT_TOP) * ratio
        parts.append(f'<line x1="{PLOT_LEFT}" y1="{y:.2f}" x2="{PLOT_RIGHT}" y2="{y:.2f}" stroke="#e5e7eb"/>')
        parts.append(f'<text x="{PLOT_LEFT - 12}" y="{y + 4:.2f}" text-anchor="end" class="axis-label">{html.escape(_format_number(value))}</text>')
    parts.append(f'<line x1="{PLOT_LEFT}" y1="{PLOT_TOP}" x2="{PLOT_LEFT}" y2="{PLOT_BOTTOM}" stroke="#64748b"/>')
    parts.append(f'<line x1="{PLOT_LEFT}" y1="{PLOT_BOTTOM}" x2="{PLOT_RIGHT}" y2="{PLOT_BOTTOM}" stroke="#64748b"/>')
    label_step = max(1, (len(rows) + 9) // 10)
    for index, row in enumerate(rows):
        if index % label_step != 0 and index != len(rows) - 1:
            continue
        x = _x_position(index, len(rows))
        label = _clip(row.get(x_column), 18)
        parts.append(f'<text x="{x:.2f}" y="{PLOT_BOTTOM + 28}" text-anchor="middle" class="axis-label">{html.escape(label)}</text>')
    if plan["chart_type"] == "line":
        for series_index, column in enumerate(y_columns):
            color = COLORS[series_index]
            points: list[str] = []
            valid_points: list[tuple[float, float, str, str]] = []
            for index, row in enumerate(rows):
                number = _chart_number(row.get(column))
                if number is None:
                    continue
                x = _x_position(index, len(rows))
                y = _y_position(number, minimum, maximum)
                points.append(f"{x:.2f},{y:.2f}")
                valid_points.append((x, y, _text(row.get(x_column)), _format_number(number)))
            if points:
                parts.append(f'<polyline points="{" ".join(points)}" fill="none" stroke="{color}" stroke-width="3" stroke-linejoin="round" stroke-linecap="round"/>')
            for x, y, x_label, formatted in valid_points:
                tooltip = html.escape(f"{x_label} · {column}: {formatted}")
                parts.append(f'<circle cx="{x:.2f}" cy="{y:.2f}" r="4.5" fill="{color}"><title>{tooltip}</title></circle>')
    else:
        group_width = max(5.0, (PLOT_RIGHT - PLOT_LEFT) / max(1, len(rows)) * 0.72)
        bar_width = max(2.0, group_width / max(1, len(y_columns)))
        zero_y = _y_position(0.0, minimum, maximum)
        for row_index, row in enumerate(rows):
            center = _x_position(row_index, len(rows))
            group_start = center - group_width / 2
            for series_index, column in enumerate(y_columns):
                number = _chart_number(row.get(column))
                if number is None:
                    continue
                value_y = _y_position(number, minimum, maximum)
                y = min(zero_y, value_y)
                height = max(1.0, abs(zero_y - value_y))
                x = group_start + series_index * bar_width
                tooltip = html.escape(f"{_text(row.get(x_column))} · {column}: {_format_number(number)}")
                parts.append(f'<rect x="{x:.2f}" y="{y:.2f}" width="{max(1.0, bar_width - 2):.2f}" height="{height:.2f}" rx="2" fill="{COLORS[series_index]}"><title>{tooltip}</title></rect>')
    legend_x = PLOT_LEFT
    for index, column in enumerate(y_columns):
        x = legend_x + index * 240
        parts.append(f'<rect x="{x}" y="18" width="14" height="14" rx="3" fill="{COLORS[index]}"/>')
        parts.append(f'<text x="{x + 21}" y="30" class="legend-label">{html.escape(column)}</text>')
    parts.append(f'<text x="{(PLOT_LEFT + PLOT_RIGHT) / 2:.2f}" y="{SVG_HEIGHT - 18}" text-anchor="middle" class="axis-title">{html.escape(x_column)}</text>')
    parts.append("</svg>")
    return "".join(parts)


# 함수 설명: 차트 아래 접근성 표에 표시할 x/y 셀만 안전하게 HTML로 변환합니다.
def _result_table(rows: list[dict[str, Any]], plan: dict[str, Any]) -> str:
    columns = [str(plan["x_column"]), *[str(column) for column in plan["y_columns"]]]
    header = "".join(f"<th>{html.escape(column)}</th>" for column in columns)
    body_rows: list[str] = []
    for row in rows:
        cells: list[str] = []
        for column in columns:
            number = _chart_number(row.get(column)) if column in plan["y_columns"] else None
            value = _format_number(number) if number is not None else _text(row.get(column))
            cells.append(f"<td>{html.escape(value)}</td>")
        body_rows.append("<tr>" + "".join(cells) + "</tr>")
    return f"<div class=\"table-wrap\"><table><thead><tr>{header}</tr></thead><tbody>{''.join(body_rows)}</tbody></table></div>"


# 주요 함수: inline CSS·SVG·데이터 표만 포함하고 외부 CDN이나 script가 없는 완전한 HTML 문서를 만듭니다.
def render_html_document(rows: list[dict[str, Any]], plan: dict[str, Any]) -> str:
    svg = render_svg_chart(rows, plan)
    table = _result_table(rows, plan)
    title = html.escape(str(plan["title"]))
    subtitle = html.escape(f"{plan['x_column']} 기준 · {', '.join(plan['y_columns'])} · {len(rows):,}개 점")
    return f"""<!doctype html>
<html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{title}</title>
<style>
:root{{color-scheme:light;font-family:Pretendard,"Noto Sans KR",Arial,sans-serif;color:#0f172a;background:#f8fafc}}*{{box-sizing:border-box}}body{{margin:0;padding:24px}}main{{max-width:1120px;margin:auto;background:white;border:1px solid #e2e8f0;border-radius:20px;padding:28px;box-shadow:0 14px 35px rgba(15,23,42,.08)}}h1{{font-size:24px;margin:0 0 8px}}p{{color:#475569;margin:0 0 22px}}svg{{width:100%;height:auto;border:1px solid #eef2f7;border-radius:16px}}.axis-label{{font-size:12px;fill:#64748b}}.axis-title{{font-size:13px;font-weight:700;fill:#334155}}.legend-label{{font-size:13px;font-weight:700;fill:#334155}}.table-wrap{{margin-top:24px;max-height:420px;overflow:auto;border:1px solid #e2e8f0;border-radius:12px}}table{{border-collapse:collapse;width:100%;font-size:13px}}th,td{{padding:9px 12px;border-bottom:1px solid #e2e8f0;text-align:left;white-space:nowrap}}th{{position:sticky;top:0;background:#f1f5f9}}
</style></head><body><main><h1>{title}</h1><p>{subtitle}</p>{svg}{table}</main></body></html>"""


# 주요 함수: result_ref 문서에서 같은 세션의 완전한 분석 결과 행만 읽고 연결을 항상 닫습니다.
def load_result_rows(question_value: Any, upstream_result_ref: Any, mongo_uri: Any, mongo_database: Any = DEFAULT_DATABASE, collection_name: Any = DEFAULT_COLLECTION, mongo_client_cls: Any = None, runtime_session_id: Any = "") -> tuple[dict[str, Any], dict[str, str] | None]:
    question, message_session_id = _message_parts(question_value)
    session_id = _text(runtime_session_id) or message_session_id
    ref_id = _ref_id(upstream_result_ref)
    if not question:
        return {}, _issue("empty_question", "시각화 요청 질문이 비어 있습니다.")
    if not ref_id:
        return {}, _issue("missing_upstream_result_ref", "시각화할 Data Analysis result_ref가 없습니다.")
    if len(ref_id) > MAX_RESULT_REF_CHARS:
        return {}, _issue("invalid_upstream_result_ref", "result_ref가 허용 길이를 초과했습니다.")
    if not session_id:
        return {}, _issue("missing_session_id", "현재 요청의 session_id를 확인할 수 없습니다.")
    uri = _text(mongo_uri)
    if not uri:
        return {}, _issue("missing_mongo_uri", "MongoDB 연결 URI가 비어 있습니다.")
    database = _text(mongo_database) or DEFAULT_DATABASE
    collection = _text(collection_name) or DEFAULT_COLLECTION
    client = None
    try:
        client_cls = mongo_client_cls or getattr(import_module("pymongo"), "MongoClient")
        client = client_cls(uri, serverSelectionTimeoutMS=5_000, connectTimeoutMS=5_000, socketTimeoutMS=5_000)
        projection = {"_id": 0, "session_id": 1, "payload.result_rows": 1, "payload.storage_manifest.result_rows": 1}
        document = client[database][collection].find_one({"_id": ref_id}, projection) or {}
        if not document:
            return {}, _issue("upstream_result_not_found", "result_ref에 해당하는 Data Analysis 결과가 없습니다.")
        stored_session = _text(document.get("session_id"))
        if not stored_session:
            return {}, _issue("upstream_session_missing", "저장된 분석 결과의 session_id가 비어 있습니다.")
        if stored_session != session_id:
            return {}, _issue("upstream_session_mismatch", "현재 요청과 다른 세션의 분석 결과는 시각화할 수 없습니다.")
        payload = document.get("payload") if isinstance(document.get("payload"), dict) else {}
        manifest = payload.get("storage_manifest") if isinstance(payload.get("storage_manifest"), dict) else {}
        result_manifest = manifest.get("result_rows") if isinstance(manifest.get("result_rows"), dict) else {}
        if result_manifest.get("complete") is False:
            return {}, _issue("upstream_result_incomplete", "저장 상한으로 잘린 분석 결과는 시각화할 수 없습니다.")
        raw_rows = payload.get("result_rows") if isinstance(payload.get("result_rows"), list) else []
        rows = [row for row in raw_rows if isinstance(row, dict)]
        if not rows:
            return {}, _issue("upstream_result_empty", "시각화할 분석 결과 행이 없습니다.")
        warnings: list[dict[str, str]] = []
        if len(rows) != len(raw_rows):
            warnings.append(_issue("invalid_rows_ignored", "dict 형식이 아닌 결과 행은 시각화에서 제외했습니다."))
        return {"question": question, "session_id": session_id, "result_ref": ref_id, "rows": rows, "row_count": len(rows), "warnings": warnings}, None
    except Exception as exc:  # noqa: BLE001
        return {}, _issue("mongo_load_error", f"분석 결과를 불러오지 못했습니다: {exc}")
    finally:
        if client is not None:
            client.close()


# 함수 설명: 실패 원인을 숨기지 않으면서 artifact가 없는 표준 오류 응답을 만듭니다.
def _error_result(error: dict[str, str]) -> dict[str, Any]:
    message = str(error.get("message") or "HTML 시각화를 생성하지 못했습니다.")
    return {"contract_version": CONTRACT_VERSION, "response_type": "html_visualization", "status": "error", "success": False, "message": f"### 시각화 오류\n{message}", "artifacts": [], "warnings": [], "errors": [error]}


# 함수 설명: 사용자 화면에 노출할 URL이 절대 http(s) 주소인지 검증해 Tauri 상대경로와 위험한 scheme을 차단합니다.
def _safe_public_url(value: Any) -> str:
    candidate = _clip(value, MAX_PUBLIC_URL_CHARS)
    if not candidate or any(ord(character) < 32 for character in candidate):
        return ""
    try:
        parsed = urlsplit(candidate)
    except ValueError:
        return ""
    if parsed.scheme.lower() not in {"http", "https"} or not parsed.hostname:
        return ""
    if parsed.username is not None or parsed.password is not None or parsed.fragment:
        return ""
    return candidate


# 함수 설명: Standalone 화면에서 입력한 서버 base URL을 Report API의 POST /reports 주소로 정규화합니다.
def _reports_post_url(value: Any) -> str:
    base_url = _safe_public_url(value)
    if not base_url:
        return ""
    normalized = base_url.rstrip("/")
    return normalized if normalized.endswith("/reports") else f"{normalized}/reports"


# 함수 설명: 링크 유효시간을 Report API가 허용하는 1시간~7일 범위의 정수로 제한합니다.
def _report_ttl_hours(value: Any) -> int:
    return _bounded_int(value, DEFAULT_REPORT_TTL_HOURS, 1, MAX_REPORT_TTL_HOURS)


# 함수 설명: 외부 패키지 없이 Report API에 JSON을 POST하고 응답 크기·형식을 제한합니다.
def _post_report_json(url: str, body: dict[str, Any], timeout_seconds: int = REPORT_API_TIMEOUT_SECONDS) -> dict[str, Any]:
    encoded = json.dumps(body, ensure_ascii=False, default=str).encode("utf-8")
    request = urllib.request.Request(
        url,
        data=encoded,
        method="POST",
        headers={"Content-Type": "application/json; charset=utf-8", "Accept": "application/json"},
    )
    try:
        with urllib.request.urlopen(request, timeout=timeout_seconds) as response:
            raw = response.read(MAX_REPORT_RESPONSE_BYTES + 1)
    except urllib.error.HTTPError as exc:
        detail = exc.read(2_000).decode("utf-8", errors="replace")
        raise RuntimeError(f"Report API HTTP {exc.code}: {_clip(detail, MAX_ERROR_CHARS)}") from exc
    except urllib.error.URLError as exc:
        raise RuntimeError(f"Report API 연결 실패: {_clip(getattr(exc, 'reason', exc), MAX_ERROR_CHARS)}") from exc
    if len(raw) > MAX_REPORT_RESPONSE_BYTES:
        raise RuntimeError("Report API 응답이 허용 크기를 초과했습니다.")
    try:
        parsed = json.loads(raw.decode("utf-8") or "{}")
    except (UnicodeDecodeError, json.JSONDecodeError) as exc:
        raise RuntimeError("Report API 응답이 올바른 UTF-8 JSON이 아닙니다.") from exc
    if not isinstance(parsed, dict):
        raise RuntimeError("Report API 응답이 JSON object 형식이 아닙니다.")
    return parsed


# 주요 함수: 생성된 HTML 원문을 Report API에 직접 보내고 공개 가능한 작은 링크 계약만 반환합니다.
def publish_html_report(
    *,
    html_document: str,
    title: str,
    question: str,
    download_name: str,
    chart_plan: dict[str, Any],
    report_api_url: Any,
    report_ttl_hours: Any,
) -> dict[str, Any]:
    post_url = _reports_post_url(report_api_url)
    if not post_url:
        raise ValueError("Report API 주소에는 절대 http(s) URL을 입력해야 합니다.")
    response = _post_report_json(
        post_url,
        {
            "html": html_document,
            "title": _clip(title, 160) or "HTML 차트",
            "question": _clip(question, MAX_QUESTION_CHARS),
            "view_request": "metadata_driven_v5 HTML/SVG chart",
            "available_datasets": [],
            "report_plan": {
                "source_flow": "10. v5_html_visualization",
                "chart_type": _clip(chart_plan.get("chart_type"), 40),
                "x_column": _clip(chart_plan.get("x_column"), 120),
                "y_columns": [_clip(item, 120) for item in chart_plan.get("y_columns", [])[:SERIES_LIMIT]],
            },
            "ttl_hours": _report_ttl_hours(report_ttl_hours),
            "filename_hint": download_name,
        },
    )
    view_url = _safe_public_url(response.get("view_url"))
    download_url = _safe_public_url(response.get("download_url"))
    if not view_url or not download_url:
        raise RuntimeError("Report API 응답에 유효한 view_url과 download_url이 모두 필요합니다.")
    return {
        "report_id": _clip(response.get("report_id"), MAX_REPORT_ID_CHARS),
        "view_url": view_url,
        "download_url": download_url,
        "expires_at": _clip(response.get("expires_at"), 80),
        "ttl_hours": _report_ttl_hours(response.get("ttl_hours") or report_ttl_hours),
    }


# 함수 설명: 모델 재작성 없이 보기·다운로드 Markdown 링크를 최종 사용자 메시지에 결정론적으로 붙입니다.
def _artifact_link_markdown(descriptor: dict[str, Any]) -> str:
    view_url = _safe_public_url(descriptor.get("view_url"))
    download_url = _safe_public_url(descriptor.get("download_url"))
    links: list[str] = []
    if view_url:
        links.append(f"[HTML 차트 보기]({view_url})")
    if download_url:
        links.append(f"[HTML 다운로드]({download_url})")
    return " · ".join(links)


# 함수 설명: 부모 Workflow에 전달할 제한된 HTML chart artifact descriptor를 구성합니다.
def _artifact_descriptor(*, path: str, title: str, download_name: str, chart_type: str, x_column: str, y_columns: list[str], row_count: int, plotted_row_count: int, size_bytes: int, report_links: dict[str, Any] | None = None) -> dict[str, Any]:
    descriptor = {"artifact_type": "html_chart", "path": path, "mime_type": "text/html", "title": _clip(title, 160), "download_name": download_name, "chart_type": chart_type, "x_column": _clip(x_column, 120), "y_columns": [_clip(column, 120) for column in y_columns[:SERIES_LIMIT]], "row_count": int(row_count), "plotted_row_count": int(plotted_row_count), "size_bytes": int(size_bytes)}
    links = report_links if isinstance(report_links, dict) else {}
    report_id = _clip(links.get("report_id"), MAX_REPORT_ID_CHARS)
    view_url = _safe_public_url(links.get("view_url"))
    download_url = _safe_public_url(links.get("download_url"))
    expires_at = _clip(links.get("expires_at"), 80)
    if report_id:
        descriptor["report_id"] = report_id
    if view_url:
        descriptor["view_url"] = view_url
    if download_url:
        descriptor["download_url"] = download_url
    if expires_at:
        descriptor["expires_at"] = expires_at
    if view_url or download_url:
        descriptor["ttl_hours"] = _report_ttl_hours(links.get("ttl_hours"))
    return descriptor


# 주요 함수: MongoDB 결과 복원부터 HTML 저장까지 한 번 수행하고 작은 visualization.result.v1 계약만 반환합니다.
# Langflow 1.8.x는 standalone Custom Component를 평가할 때 모듈 최상위 AsyncFunctionDef를
# 실행 전역에 포함하지 않으므로, 동기 함수가 내부 coroutine을 만들어 반환하는 형태를 사용합니다.
def build_html_visualization(*, question_value: Any, upstream_result_ref: Any, mongo_uri: Any, mongo_database: Any = DEFAULT_DATABASE, collection_name: Any = DEFAULT_COLLECTION, max_chart_rows: Any = DEFAULT_MAX_CHART_ROWS, report_api_url: Any = DEFAULT_REPORT_API_URL, report_ttl_hours: Any = DEFAULT_REPORT_TTL_HOURS, flow_id: Any, storage_service: Any, mongo_client_cls: Any = None, report_publisher_fn: Any = None, file_token: str = "", runtime_session_id: Any = ""):
    # 함수 설명: `_run()`은 MongoDB 복원, 차트 생성, 파일 저장을 하나의 await 가능한 실행 단위로 묶습니다.
    async def _run() -> dict[str, Any]:
        source, source_error = load_result_rows(question_value, upstream_result_ref, mongo_uri, mongo_database, collection_name, mongo_client_cls, runtime_session_id)
        if source_error:
            return _error_result(source_error)
        plan, plan_error = select_chart_plan(source["rows"], source["question"])
        if plan_error:
            return _error_result(plan_error)
        ordered = _ordered_rows(source["rows"], str(plan["x_column"]))
        row_limit = _bounded_int(max_chart_rows, DEFAULT_MAX_CHART_ROWS, 10, MAX_CHART_ROWS)
        plotted_rows, sampled = _sample_rows(ordered, row_limit)
        warnings = list(source.get("warnings") or [])
        if sampled:
            warnings.append(_issue("chart_rows_sampled", f"{len(ordered):,}개 행을 {len(plotted_rows):,}개 점으로 균등 축소했습니다."))
        html_document = render_html_document(plotted_rows, plan)
        encoded = html_document.encode("utf-8")
        if len(encoded) > MAX_HTML_BYTES:
            return _error_result(_issue("html_size_limit_exceeded", "생성된 HTML이 허용 크기를 초과했습니다."))
        runtime_flow_id = _text(flow_id)
        if not runtime_flow_id:
            return _error_result(_issue("missing_flow_id", "HTML을 저장할 현재 Flow ID를 확인할 수 없습니다."))
        if storage_service is None or not callable(getattr(storage_service, "save_file", None)):
            return _error_result(_issue("storage_service_unavailable", "Langflow 파일 저장소를 사용할 수 없습니다."))
        safe_token = re.sub(r"[^a-zA-Z0-9]", "", file_token)[:32] or uuid.uuid4().hex
        download_name = f"html-chart-{safe_token}.html"
        path = f"{runtime_flow_id}/{download_name}"
        try:
            await storage_service.save_file(flow_id=runtime_flow_id, file_name=download_name, data=encoded, append=False)
        except Exception as exc:  # noqa: BLE001
            return _error_result(_issue("html_storage_error", f"HTML 파일을 저장하지 못했습니다: {exc}"))
        report_links: dict[str, Any] = {}
        configured_report_api = _text(report_api_url)
        if configured_report_api:
            publisher = report_publisher_fn if callable(report_publisher_fn) else publish_html_report
            try:
                report_links = await asyncio.to_thread(
                    publisher,
                    html_document=html_document,
                    title=str(plan["title"]),
                    question=str(source["question"]),
                    download_name=download_name,
                    chart_plan=plan,
                    report_api_url=configured_report_api,
                    report_ttl_hours=report_ttl_hours,
                )
            except Exception as exc:  # noqa: BLE001
                warnings.append(_issue("report_api_publish_error", f"HTML은 생성했지만 보기/다운로드 링크를 만들지 못했습니다: {exc}"))
        else:
            warnings.append(_issue("report_api_disabled", "Report API 주소가 비어 있어 보기/다운로드 링크를 만들지 않았습니다."))

        descriptor = _artifact_descriptor(path=path, title=str(plan["title"]), download_name=download_name, chart_type=str(plan["chart_type"]), x_column=str(plan["x_column"]), y_columns=list(plan["y_columns"]), row_count=int(source["row_count"]), plotted_row_count=len(plotted_rows), size_bytes=len(encoded), report_links=report_links)
        link_markdown = _artifact_link_markdown(descriptor)
        message = "### HTML 시각화\n" + f"{descriptor['title']} 차트를 생성했습니다.\n\n" + f"- 차트 유형: `{descriptor['chart_type']}`\n" + f"- X축: `{descriptor['x_column']}`\n" + f"- Y축: `{', '.join(descriptor['y_columns'])}`\n" + f"- 데이터: 전체 {descriptor['row_count']:,}건, 표시 {descriptor['plotted_row_count']:,}건"
        if link_markdown:
            message += f"\n\n{link_markdown}"
            if descriptor.get("expires_at"):
                message += f"\n\n- 링크 만료: `{descriptor['expires_at']}`"
        else:
            message += "\n\nHTML 파일은 생성했지만 공개 링크를 만들지 못했습니다. Report API 서버 주소와 실행 상태를 확인해 주세요."
        status = "ok" if link_markdown else "partial"
        summary = f"{descriptor['x_column']} 기준 {', '.join(descriptor['y_columns'])} {descriptor['chart_type']} HTML 차트를 생성했습니다."
        return {"contract_version": CONTRACT_VERSION, "response_type": "html_visualization", "status": status, "success": True, "summary": _clip(summary, 500), "message": message, "artifacts": [descriptor], "warnings": warnings, "errors": []}

    return _run()


# 함수 설명: 실제 Langflow 서비스 관리자에서 현재 파일 저장소를 가져옵니다.
def _runtime_storage_service() -> Any:
    try:
        deps = import_module("lfx.services.deps")
        return getattr(deps, "get_storage_service")()
    except Exception:  # noqa: BLE001
        return None


# Langflow 컴포넌트 클래스: 하나의 custom node에서 결과 복원·차트 생성·Message/API 출력을 모두 제공해 Flow 구조를 단순하게 유지합니다.
class HTMLVisualizationBuilder(Component):
    display_name = "00 HTML 시각화 생성기"
    description = "Data Analysis result_ref를 복원해 외부 CDN 없는 HTML/SVG 차트를 생성합니다."
    name = "HTMLVisualizationBuilder"
    icon = "ChartNoAxesCombined"
    inputs = [
        HandleInput(name="question", display_name="시각화 질문", info="Chat Input에서 전달된 현재 사용자 질문입니다.", input_types=["Message"], required=True),
        MessageTextInput(name="upstream_result_ref", display_name="상위 분석 결과 참조", info="바로 앞 Data Analysis Tool이 반환한 result_ref입니다.", value="", required=False, advanced=False),
        MessageTextInput(name="mongo_uri", display_name="MongoDB 연결 URI", info="Standalone Langflow Global Variable MONGO_URL을 선택합니다.", value="MONGO_URL", load_from_db=True, required=False, advanced=False),
        MessageTextInput(name="mongo_database", display_name="MongoDB 데이터베이스", value=DEFAULT_DATABASE, required=False, advanced=False),
        MessageTextInput(name="collection_name", display_name="결과 컬렉션", value=DEFAULT_COLLECTION, required=False, advanced=False),
        MessageTextInput(name="report_api_url", display_name="HTML Report API 주소", info="보기·다운로드 절대 URL을 발급하는 서버 주소입니다. 예: http://127.0.0.1:8010", value=DEFAULT_REPORT_API_URL, required=False, advanced=False),
        StrInput(name="report_ttl_hours", display_name="HTML 링크 유효시간", info="링크 유지 시간입니다. 1~168시간 범위로 제한합니다.", value=str(DEFAULT_REPORT_TTL_HOURS), required=False, advanced=False),
        StrInput(name="max_chart_rows", display_name="최대 차트 행 수", info="행이 더 많으면 첫·끝을 포함해 균등 축소합니다.", value=str(DEFAULT_MAX_CHART_ROWS), advanced=True),
    ]
    outputs = [
        Output(
            name="message",
            display_name="시각화 메시지",
            method="build_message",
            types=["Message"],
            group_outputs=True,
        ),
        Output(
            name="api_response",
            display_name="API 응답",
            method="build_api_response",
            types=["Data"],
            group_outputs=True,
        ),
    ]

    # 주요 메서드: 두 출력이 동시에 요청되어도 하나의 task를 공유해 Mongo 조회와 파일 저장을 정확히 한 번만 수행합니다.
    async def _result_once(self) -> dict[str, Any]:
        task = getattr(self, "_visualization_result_task", None)
        if task is None:
            task = asyncio.create_task(self._execute_visualization())
            self._visualization_result_task = task
        return await task

    # 주요 메서드: standalone 화면 입력과 현재 Flow 저장소를 순수 실행 함수에 연결합니다.
    async def _execute_visualization(self) -> dict[str, Any]:
        graph = getattr(self, "graph", None)
        runtime_session_id = str(
            getattr(graph, "session_id", "") or getattr(self, "_session_id", "") or ""
        ).strip()
        return await build_html_visualization(question_value=getattr(self, "question", None), upstream_result_ref=getattr(self, "upstream_result_ref", ""), mongo_uri=getattr(self, "mongo_uri", ""), mongo_database=getattr(self, "mongo_database", DEFAULT_DATABASE), collection_name=getattr(self, "collection_name", DEFAULT_COLLECTION), max_chart_rows=getattr(self, "max_chart_rows", DEFAULT_MAX_CHART_ROWS), report_api_url=getattr(self, "report_api_url", DEFAULT_REPORT_API_URL), report_ttl_hours=getattr(self, "report_ttl_hours", DEFAULT_REPORT_TTL_HOURS), flow_id=getattr(self, "flow_id", ""), storage_service=_runtime_storage_service(), runtime_session_id=runtime_session_id)

    # Langflow 출력 함수: HTML 경로가 첨부된 단일 AI Message를 Chat Output에 전달합니다.
    async def build_message(self) -> Message:
        result = await self._result_once()
        message = Message(text=str(result.get("message") or ""))
        message.files = [item["path"] for item in result.get("artifacts", []) if isinstance(item, dict) and item.get("path")]
        message.error = str(result.get("status") or "") == "error"
        message.category = "error" if message.error else "message"
        self.status = message
        return message

    # Langflow 출력 함수: raw rows/HTML 없이 artifact descriptor만 포함한 terminal API Data를 반환합니다.
    async def build_api_response(self) -> Data:
        result = await self._result_once()
        self.status = str(result.get("message") or "")
        return Data(data=result)
